{
  "name": "Lumina Space: AI Interior Designer",
  "description": "Transform your living space with AI-driven interior design. Upload a photo, reimagine it in various styles like Scandinavian or Mid-Century Modern, and chat with an AI consultant to refine your vision and find shoppable items.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum DesignStyle {
  MID_CENTURY_MODERN = 'Mid-Century Modern',
  SCANDINAVIAN = 'Scandinavian',
  INDUSTRIAL = 'Industrial',
  MINIMALIST = 'Minimalist',
  BOHEMIAN = 'Bohemian',
  JAPANDI = 'Japandi',
  CONTEMPORARY = 'Contemporary',
  RUSTIC = 'Rustic'
}

export interface DesignVariant {
  id: string;
  style: DesignStyle;
  imageUrl: string;
  prompt: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { DesignStyle } from "../types";

const MODEL_IMAGE = 'gemini-2.5-flash-image';
const MODEL_CHAT = 'gemini-3-pro-preview';

export const generateReimaginedDesign = async (
  originalImageBase64: string,
  style: DesignStyle
): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `Reimagine this room in a ${style} interior design style. Keep the basic structural layout but update all furniture, textures, lighting, and decor to match the ${style} aesthetic. Ensure high quality and realistic materials.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: {
        parts: [
          {
            inlineData: {
              data: originalImageBase64.split(',')[1],
              mimeType: 'image/png'
            }
          },
          { text: prompt }
        ]
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Error generating image:", error);
  }
  return null;
};

export const editDesign = async (
  currentImageBase64: string,
  instruction: string
): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: {
        parts: [
          {
            inlineData: {
              data: currentImageBase64.split(',')[1],
              mimeType: 'image/png'
            }
          },
          { text: instruction }
        ]
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Error editing image:", error);
  }
  return null;
};

export const getDesignAdvice = async (
  userPrompt: string,
  imageBase64?: string
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const systemInstruction = `You are a world-class Interior Design Consultant named Lumina. 
  Your goal is to help users refine their home designs. 
  Provide professional, encouraging, and detailed advice. 
  When asked about specific items, suggest high-quality shoppable styles or materials. 
  If an image is provided, analyze the style, color palette, and layout to give context-aware suggestions.
  Always format your response with clear headings or bullet points if needed.`;

  try {
    const parts: any[] = [{ text: userPrompt }];
    if (imageBase64) {
      parts.push({
        inlineData: {
          data: imageBase64.split(',')[1],
          mimeType: 'image/png'
        }
      });
    }

    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: { parts },
      config: {
        systemInstruction,
        temperature: 0.7,
      }
    });

    return response.text || "I'm sorry, I couldn't generate a response. Please try again.";
  } catch (error) {
    console.error("Error in chat service:", error);
    return "I'm having a bit of trouble connecting to my design brain. Please check your connection!";
  }
};

import React, { useState, useRef, useEffect } from 'react';

interface CompareSliderProps {
  original: string;
  modified: string;
}

const CompareSlider: React.FC<CompareSliderProps> = ({ original, modified }) => {
  const [sliderPos, setSliderPos] = useState(50);
  const containerRef = useRef<HTMLDivElement>(null);

  const handleMove = (clientX: number) => {
    if (containerRef.current) {
      const rect = containerRef.current.getBoundingClientRect();
      const x = Math.max(0, Math.min(clientX - rect.left, rect.width));
      setSliderPos((x / rect.width) * 100);
    }
  };

  const onMouseMove = (e: React.MouseEvent) => handleMove(e.clientX);
  const onTouchMove = (e: React.TouchEvent) => handleMove(e.touches[0].clientX);

  return (
    <div 
      ref={containerRef}
      className="relative w-full aspect-video md:aspect-[16/9] bg-slate-200 rounded-2xl overflow-hidden cursor-ew-resize select-none border-4 border-white shadow-2xl"
      onMouseMove={onMouseMove}
      onTouchMove={onTouchMove}
    >
      {/* After Image (Full width) */}
      <img 
        src={modified} 
        alt="Modified Room" 
        className="absolute inset-0 w-full h-full object-cover"
      />

      {/* Before Image (Clipped width) */}
      <div 
        className="absolute inset-0 overflow-hidden border-r border-white/30"
        style={{ width: `${sliderPos}%` }}
      >
        <img 
          src={original} 
          alt="Original Room" 
          className="absolute inset-0 w-full h-full object-cover grayscale-[0.2]"
          style={{ width: `${100 / (sliderPos / 100)}%` }} // Simple fix for aspect ratio scale
        />
        {/* Aspect ratio hack: The above scale is tricky. Let's just use object-cover and standard width */}
        <img 
          src={original} 
          alt="Original Room" 
          className="w-[100vw] h-full object-cover max-w-none"
          style={{ width: containerRef.current?.offsetWidth }}
        />
      </div>

      {/* Labels */}
      <div className="absolute bottom-4 left-4 bg-black/50 backdrop-blur-md text-white text-xs px-2 py-1 rounded font-medium">ORIGINAL</div>
      <div className="absolute bottom-4 right-4 bg-indigo-600/70 backdrop-blur-md text-white text-xs px-2 py-1 rounded font-medium">REIMAGINED</div>

      {/* Slider Line */}
      <div 
        className="absolute top-0 bottom-0 w-1 bg-white shadow-[0_0_10px_rgba(0,0,0,0.3)] pointer-events-none"
        style={{ left: `${sliderPos}%` }}
      >
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-8 h-8 bg-white rounded-full flex items-center justify-center shadow-lg border-2 border-slate-300">
          <svg className="w-4 h-4 text-slate-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7l-5 5m0 0l5 5m-5-5h18m-5-5l5 5m0 0l-5 5" />
          </svg>
        </div>
      </div>
    </div>
  );
};

export default CompareSlider;

