import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { getDesignAdvice } from '../services/geminiService';

interface ChatInterfaceProps {
  currentImage: string | null;
  onEditRequested: (instruction: string) => void;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ currentImage, onEditRequested }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: "Hi! I'm Lumina, your AI interior design consultant. How can I help you refine your space today?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userText = input.trim();
    const newUserMsg: ChatMessage = { role: 'user', text: userText, timestamp: Date.now() };
    setMessages(prev => [...prev, newUserMsg]);
    setInput('');
    setIsLoading(true);

    // Heuristic: If user asks to "change", "add", "make", "remove" something in the image, trigger editing
    const editKeywords = ['change', 'add', 'remove', 'make', 'put', 'filter', 'swap', 'replace'];
    const isEditRequest = editKeywords.some(keyword => userText.toLowerCase().includes(keyword));

    if (isEditRequest && currentImage) {
        onEditRequested(userText);
    }

    const aiResponse = await getDesignAdvice(userText, currentImage || undefined);
    const newAiMsg: ChatMessage = { role: 'model', text: aiResponse, timestamp: Date.now() };
    setMessages(prev => [...prev, newAiMsg]);
    setIsLoading(false);
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-100">
      <div className="p-4 bg-slate-900 text-white flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center font-bold text-lg">L</div>
          <div>
            <h4 className="font-bold text-sm">Lumina AI Consultant</h4>
            <p className="text-[10px] text-slate-300 flex items-center gap-1">
              <span className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse"></span>
              Online for your design needs
            </p>
          </div>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl p-4 shadow-sm text-sm ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-white text-slate-800 border border-slate-200 rounded-tl-none'
            }`}>
              <div className="whitespace-pre-wrap leading-relaxed">{msg.text}</div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white text-slate-400 border border-slate-200 rounded-2xl rounded-tl-none p-4 shadow-sm flex items-center gap-2">
              <div className="flex gap-1">
                <span className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce"></span>
                <span className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                <span className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce [animation-delay:0.4s]"></span>
              </div>
              <span className="text-xs italic">Lumina is thinking...</span>
            </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSend} className="p-4 bg-white border-t border-slate-100 flex gap-2">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Refine the design or ask for advice..."
          className="flex-1 bg-slate-100 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
        />
        <button
          type="submit"
          disabled={!input.trim() || isLoading}
          className="w-12 h-12 bg-indigo-600 text-white rounded-xl flex items-center justify-center hover:bg-indigo-700 transition-colors disabled:bg-slate-300 disabled:cursor-not-allowed"
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
          </svg>
        </button>
      </form>
    </div>
  );
};

export default ChatInterface;

import React, { useState, useCallback } from 'react';
import ImageUpload from './components/ImageUpload';
import StyleCarousel from './components/StyleCarousel';
import CompareSlider from './components/CompareSlider';
import ChatInterface from './components/ChatInterface';
import { DesignStyle } from './types';
import { generateReimaginedDesign, editDesign } from './services/geminiService';

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleImageUpload = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
    setError(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage) return;

    setSelectedStyle(style);
    setIsGenerating(true);
    setError(null);

    const result = await generateReimaginedDesign(originalImage, style);
    if (result) {
      setModifiedImage(result);
    } else {
      setError("Failed to generate design. Please try again.");
    }
    setIsGenerating(false);
  };

  const handleEditRequested = async (instruction: string) => {
    const baseImage = modifiedImage || originalImage;
    if (!baseImage) return;

    setIsGenerating(true);
    const result = await editDesign(baseImage, instruction);
    if (result) {
      setModifiedImage(result);
    }
    setIsGenerating(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-200 py-4 px-6 mb-8">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center">
              <svg className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
              </svg>
            </div>
            <h1 className="text-2xl font-bold tracking-tight text-slate-900">
              Lumina <span className="text-indigo-600 font-light">Space</span>
            </h1>
          </div>
          <div className="hidden md:flex gap-6 text-sm font-medium text-slate-500">
            <a href="#" className="hover:text-indigo-600">Home</a>
            <a href="#" className="hover:text-indigo-600">Portfolio</a>
            <a href="#" className="hover:text-indigo-600">Pricing</a>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 md:px-6">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Controls & Visualization */}
          <div className="lg:col-span-8 space-y-8">

            {/* Step 1: Upload */}
            {!originalImage && (
              <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 text-center space-y-6 animate-in fade-in slide-in-from-bottom-4">
                <div className="max-w-md mx-auto space-y-4">
                  <h2 className="text-3xl font-bold text-slate-900">Let's transform your room</h2>
                  <p className="text-slate-500">Upload a photo of any space—living room, bedroom, or office—and see it reborn with AI magic.</p>
                </div>
                <ImageUpload onImageUpload={handleImageUpload} />
              </div>
            )}

            {/* Step 2: Main Viewer */}
            {originalImage && (
              <div className="space-y-6 animate-in fade-in duration-500">
                <div className="flex items-center justify-between">
                  <h2 className="text-2xl font-bold text-slate-900">Design Studio</h2>
                  <button 
                    onClick={() => { setOriginalImage(null); setModifiedImage(null); setSelectedStyle(null); }}
                    className="text-sm font-medium text-slate-500 hover:text-indigo-600 flex items-center gap-1 transition-colors"
                  >
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                    </svg>
                    Start Over
                  </button>
                </div>

                {/* Compare Slider or Loading State */}
                <div className="relative">
                  {isGenerating && (
                    <div className="absolute inset-0 z-10 bg-white/60 backdrop-blur-sm rounded-2xl flex flex-col items-center justify-center p-8 text-center animate-in fade-in">
                      <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
                      <h4 className="text-xl font-bold text-slate-800">Visualizing your space...</h4>
                      <p className="text-slate-500 max-w-xs mt-2">Our AI is meticulously rendering your room in the {selectedStyle} style.</p>
                    </div>
                  )}

                  {modifiedImage ? (
                    <CompareSlider original={originalImage} modified={modifiedImage} />
                  ) : (
                    <div className="w-full aspect-video md:aspect-[16/9] bg-slate-200 rounded-2xl overflow-hidden border-4 border-white shadow-xl">
                      <img src={originalImage} alt="Original" className="w-full h-full object-cover" />
                    </div>
                  )}
                </div>

                {/* Style Selector */}
                <StyleCarousel 
                  onSelect={handleStyleSelect} 
                  selectedStyle={selectedStyle} 
                  isGenerating={isGenerating} 
                />

                {error && (
                  <div className="p-4 bg-red-50 text-red-600 rounded-xl border border-red-100 text-sm font-medium">
                    {error}
                  </div>
                )}
              </div>
            )}
          </div>

          {/* Right Column: AI Consultant Chat */}
          <div className="lg:col-span-4">
            <div className="sticky top-24">
              <ChatInterface 
                currentImage={modifiedImage || originalImage} 
                onEditRequested={handleEditRequested}
              />

              <div className="mt-6 p-6 bg-indigo-900 rounded-3xl text-white shadow-lg overflow-hidden relative">
                <div className="relative z-10">
                  <h4 className="font-bold text-lg mb-2">Design Pro Tip</h4>
                  <p className="text-indigo-100 text-sm leading-relaxed">
                    Try asking Lumina: "Which floor lamp would best suit this Scandinavian setup?" or "Make the walls a soft sage green."
                  </p>
                </div>
                <div className="absolute -right-4 -bottom-4 w-24 h-24 bg-indigo-500 rounded-full blur-2xl opacity-50"></div>
                <div className="absolute -left-4 -top-4 w-24 h-24 bg-blue-500 rounded-full blur-2xl opacity-20"></div>
              </div>
            </div>
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useCallback } from 'react';

interface ImageUploadProps {
  onImageUpload: (base64: string) => void;
}

const ImageUpload: React.FC<ImageUploadProps> = ({ onImageUpload }) => {
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onImageUpload(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    const file = e.dataTransfer.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onImageUpload(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div 
      onDragOver={onDragOver}
      onDrop={onDrop}
      className="group relative border-2 border-dashed border-slate-300 hover:border-indigo-500 hover:bg-indigo-50/50 rounded-3xl p-12 transition-all cursor-pointer overflow-hidden"
    >
      <input 
        type="file" 
        accept="image/*" 
        onChange={handleFileChange} 
        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
      />
      <div className="flex flex-col items-center gap-4">
        <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center group-hover:bg-indigo-100 transition-colors">
          <svg className="w-8 h-8 text-slate-400 group-hover:text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
          </svg>
        </div>
        <div className="space-y-1">
          <p className="text-lg font-bold text-slate-900">Upload Room Photo</p>
          <p className="text-sm text-slate-500 font-medium uppercase tracking-tight">Drag and drop or click to browse</p>
        </div>
        <p className="text-xs text-slate-400 mt-4">JPG, PNG or WEBP (max. 10MB)</p>
      </div>
    </div>
  );
};

export default ImageUpload;

import React, { useState, useRef, useCallback } from 'react';

interface ImageInputProps {
  onImageSelected: (base64: string) => void;
}

const ImageInput: React.FC<ImageInputProps> = ({ onImageSelected }) => {
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' }, 
        audio: false 
      });
      setStream(mediaStream);
      setIsCameraActive(true);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
    } catch (err) {
      console.error("Error accessing camera:", err);
      alert("Could not access camera. Please check permissions.");
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    setIsCameraActive(false);
  }, [stream]);

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/png');
        stopCamera();
        onImageSelected(base64);
      }
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onImageSelected(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const onDragOver = (e: React.DragEvent) => e.preventDefault();
  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    const file = e.dataTransfer.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => onImageSelected(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  if (isCameraActive) {
    return (
      <div className="relative bg-slate-900 rounded-3xl overflow-hidden aspect-video md:aspect-[16/9] shadow-2xl animate-in fade-in zoom-in-95 duration-300">
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="w-full h-full object-cover"
        />
        <div className="absolute top-4 left-4 flex items-center gap-2 px-3 py-1.5 bg-red-600 text-white text-[10px] font-bold rounded-full uppercase tracking-widest animate-pulse">
          <span className="w-2 h-2 bg-white rounded-full"></span>
          Live Camera
        </div>
        <div className="absolute bottom-8 left-0 right-0 flex justify-center items-center gap-6">
          <button 
            onClick={stopCamera}
            className="w-14 h-14 bg-white/10 backdrop-blur-md border border-white/20 text-white rounded-full flex items-center justify-center hover:bg-white/20 transition-all"
            title="Cancel"
          >
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>

          <button 
            onClick={capturePhoto}
            className="w-20 h-20 bg-white rounded-full flex items-center justify-center shadow-xl hover:scale-105 active:scale-95 transition-all group"
            title="Capture Photo"
          >
            <div className="w-16 h-16 border-4 border-slate-900 rounded-full flex items-center justify-center group-hover:bg-slate-50">
               <div className="w-12 h-12 bg-indigo-600 rounded-full"></div>
            </div>
          </button>

          <div className="w-14 h-14"></div> {/* Spacer for balance */}
        </div>
        <canvas ref={canvasRef} className="hidden" />
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
      {/* Upload Box */}
      <div 
        onDragOver={onDragOver}
        onDrop={onDrop}
        className="group relative border-2 border-dashed border-slate-300 hover:border-indigo-500 hover:bg-indigo-50/50 rounded-3xl p-10 transition-all cursor-pointer overflow-hidden flex flex-col items-center text-center justify-center min-h-[280px]"
      >
        <input 
          type="file" 
          accept="image/*" 
          onChange={handleFileChange} 
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
        />
        <div className="w-14 h-14 bg-slate-100 rounded-full flex items-center justify-center group-hover:bg-indigo-100 transition-colors mb-4">
          <svg className="w-7 h-7 text-slate-400 group-hover:text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
          </svg>
        </div>
        <div className="space-y-1">
          <p className="text-lg font-bold text-slate-900">Upload Photo</p>
          <p className="text-xs text-slate-500 font-medium uppercase tracking-tight">JPG, PNG or WEBP</p>
        </div>
      </div>

      {/* Camera Box */}
      <button 
        onClick={startCamera}
        className="group relative border-2 border-slate-100 bg-white hover:border-indigo-500 hover:bg-indigo-50/50 rounded-3xl p-10 transition-all flex flex-col items-center text-center justify-center min-h-[280px] shadow-sm"
      >
        <div className="w-14 h-14 bg-indigo-50 rounded-full flex items-center justify-center group-hover:bg-indigo-100 transition-colors mb-4">
          <svg className="w-7 h-7 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
          </svg>
        </div>
        <div className="space-y-1">
          <p className="text-lg font-bold text-slate-900">Take Photo</p>
          <p className="text-xs text-slate-500 font-medium uppercase tracking-tight">Use your camera directly</p>
        </div>
      </button>
    </div>
  );
};

