import React, { useState, useRef } from 'react';
import { 
  StyleSheet, 
  View, 
  Text, 
  TextInput, 
  TouchableOpacity, 
  ScrollView,
  Linking,
  ActivityIndicator
} from 'react-native';
import { ChatMessage } from '../types';
import { getDesignAdvice } from '../services/geminiService';

interface ChatInterfaceProps {
  currentImage: string | null;
  onEditRequested: (instruction: string) => void;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ currentImage }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: "Hi! I'm Lumina, your AI consultant. How can I help?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<ScrollView>(null);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userText = input.trim();
    const newUserMsg: ChatMessage = { role: 'user', text: userText, timestamp: Date.now() };
    setMessages(prev => [...prev, newUserMsg]);
    setInput('');
    setIsLoading(true);

    const { text, links } = await getDesignAdvice(userText, currentImage || undefined);
    const newAiMsg: ChatMessage = { role: 'model', text, links, timestamp: Date.now() };
    setMessages(prev => [...prev, newAiMsg]);
    setIsLoading(false);

    setTimeout(() => scrollRef.current?.scrollToEnd({ animated: true }), 100);
  };

  return (
    <View style={styles.container}>
      <View style={styles.chatHeader}>
        <View style={styles.avatar}>
           <Text style={styles.avatarText}>L</Text>
        </View>
        <Text style={styles.headerTitle}>Lumina AI Consultant</Text>
      </View>

      <ScrollView 
        ref={scrollRef} 
        style={styles.msgContainer}
        contentContainerStyle={{ paddingBottom: 20 }}
      >
        {messages.map((msg, i) => (
          <View key={i} style={[
            styles.bubble, 
            msg.role === 'user' ? styles.userBubble : styles.modelBubble
          ]}>
            <Text style={[
              styles.msgText,
              msg.role === 'user' ? { color: '#fff' } : { color: '#1e293b' }
            ]}>{msg.text}</Text>

            {msg.links?.map((link, idx) => (
              <TouchableOpacity 
                key={idx} 
                onPress={() => Linking.openURL(link.uri)}
                style={styles.linkBtn}
              >
                <Text style={styles.linkText}>🛍️ {link.title}</Text>
              </TouchableOpacity>
            ))}
          </View>
        ))}
        {isLoading && (
          <View style={[styles.bubble, styles.modelBubble]}>
            <ActivityIndicator size="small" color="#4f46e5" />
          </View>
        )}
      </ScrollView>

      <View style={styles.inputRow}>
        <TextInput
          style={styles.input}
          placeholder="Ask about design..."
          value={input}
          onChangeText={setInput}
        />
        <TouchableOpacity style={styles.sendBtn} onPress={handleSend}>
          <Text style={styles.sendBtnText}>→</Text>
        </TouchableOpacity>
      </View>
    </View>
  );
};

