} from 'react-native';

interface ImageInputProps {
  onImageSelected: (base64: string) => void;
}

const ImageInput: React.FC<ImageInputProps> = ({ onImageSelected }) => {
  // In a real RN app, we would use react-native-image-picker here.
  // For this environment, we'll simulate a file selector.

  const handleSimulatedPick = () => {
    // In a real device, this would call ImagePicker.launchImageLibraryAsync
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e: any) => {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = () => onImageSelected(reader.result as string);
      reader.readAsDataURL(file);
    };
    input.click();
  };

  return (
    <View style={styles.container}>
      <TouchableOpacity style={styles.uploadBox} onPress={handleSimulatedPick}>
        <Text style={styles.icon}>📁</Text>
        <Text style={styles.boxTitle}>Upload Photo</Text>
        <Text style={styles.boxSub}>Gallery</Text>
      </TouchableOpacity>

      <TouchableOpacity style={styles.cameraBox} onPress={handleSimulatedPick}>
        <Text style={styles.icon}>📸</Text>
        <Text style={styles.boxTitle}>Take Photo</Text>
        <Text style={styles.boxSub}>Camera</Text>
      </TouchableOpacity>
    </View>
  );
};

