  Dimensions,
  ActivityIndicator
} from 'react-native';
import ImageInput from './components/ImageInput';
import StyleCarousel from './components/StyleCarousel';
import CompareSlider from './components/CompareSlider';
import ChatInterface from './components/ChatInterface';
import { DesignStyle, SavedDesign } from './types';
import { generateReimaginedDesign } from './services/geminiService';

const { width: windowWidth } = Dimensions.get('window');

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage) return;
    setSelectedStyle(style);
    setIsGenerating(true);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      } else {
        Alert.alert("Error", "Failed to generate design.");
      }
    } catch (e) {
      console.error(e);
      Alert.alert("Error", "An unexpected error occurred.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleShuffleStyle = () => {
    if (!originalImage || isGenerating) return;
    const allStyles = Object.values(DesignStyle);
    const availableStyles = allStyles.filter(s => s !== selectedStyle);
    const randomStyle = availableStyles[Math.floor(Math.random() * availableStyles.length)];
    handleStyleSelect(randomStyle);
  };

  const handleSaveDesign = () => {
    if (!originalImage || !modifiedImage || !selectedStyle) return;
    const newSaved: SavedDesign = {
      id: Date.now().toString(),
      originalImage,
      modifiedImage,
      style: selectedStyle,
      timestamp: Date.now()
    };
    setSavedDesigns(prev => [newSaved, ...prev]);
    Alert.alert("Saved", "Design added to your gallery!");
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.logoText}>Lumina <Text style={styles.logoAccent}>Space</Text></Text>
      </View>

      <ScrollView contentContainerStyle={styles.scrollContent}>
        {!originalImage ? (
          <View style={styles.welcomeCard}>
            <Text style={styles.welcomeTitle}>Reimagine your space</Text>
            <Text style={styles.welcomeSubtitle}>Snap a photo and see it transformed instantly with AI.</Text>
            <ImageInput onImageSelected={handleImageInput} />
          </View>
        ) : (
          <View style={styles.studioContainer}>
            <View style={styles.studioHeader}>
              <Text style={styles.sectionTitle}>Design Studio</Text>
              <TouchableOpacity onPress={() => {setOriginalImage(null); setModifiedImage(null);}}>
                <Text style={styles.resetText}>New Design</Text>
              </TouchableOpacity>
            </View>

            <View style={styles.viewerContainer}>
              {isGenerating && (
                <View style={styles.loaderOverlay}>
                  <ActivityIndicator size="large" color="#4f46e5" />
                  <Text style={styles.loaderText}>Rendering {selectedStyle}...</Text>
                </View>
              )}
              {modifiedImage ? (
                <CompareSlider original={originalImage} modified={modifiedImage} />
              ) : (
                <View style={styles.placeholderImage}>
                   <CompareSlider original={originalImage} modified={originalImage} />
                </View>
              )}
            </View>

            <StyleCarousel 
              onSelect={handleStyleSelect} 
              selectedStyle={selectedStyle} 
              isGenerating={isGenerating} 
            />

            <View style={styles.actionsRow}>
              {modifiedImage && (
                <>
                  <TouchableOpacity style={styles.shuffleBtn} onPress={handleShuffleStyle} disabled={isGenerating}>
                    <Text style={styles.shuffleBtnText}>Shuffle Style</Text>
                  </TouchableOpacity>
                  <TouchableOpacity style={styles.saveBtn} onPress={handleSaveDesign}>
                    <Text style={styles.saveBtnText}>Save to Gallery</Text>
                  </TouchableOpacity>
                </>
              )}
            </View>

            <View style={styles.chatSection}>
              <ChatInterface 
                currentImage={modifiedImage || originalImage} 
                onEditRequested={(instr) => console.log('Edit requested:', instr)}
              />
            </View>
          </View>
        )}

        {savedDesigns.length > 0 && (
          <View style={styles.gallerySection}>
            <Text style={styles.sectionTitle}>Your Projects</Text>
            <ScrollView horizontal showsHorizontalScrollIndicator={false} style={styles.galleryScroll}>
              {savedDesigns.map((item) => (
                <View key={item.id} style={styles.galleryCard}>
                  <View style={styles.galleryImageContainer}>
                    <CompareSlider original={item.originalImage} modified={item.modifiedImage} />
                  </View>
                  <Text style={styles.galleryStyleText}>{item.style}</Text>
                </View>
              ))}
            </ScrollView>
          </View>
        )}
      </ScrollView>
    </SafeAreaView>
  );
};

