import React from 'react';
import { 
  StyleSheet, 
  View, 
  Text, 
  TouchableOpacity,
  Platform,
  Alert
} from 'react-native';
import * as ImagePicker from 'expo-image-picker';

interface ImageInputProps {
  onImageSelected: (base64: string) => void;
}

const ImageInput: React.FC<ImageInputProps> = ({ onImageSelected }) => {

  const handlePickImage = async (useCamera: boolean) => {
    try {
      if (Platform.OS === 'web') {
        // Web fallback for browser preview
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = 'image/*';
        if (useCamera) input.capture = 'environment';
        input.onchange = (e: any) => {
          const file = e.target.files[0];
          const reader = new FileReader();
          reader.onload = () => onImageSelected(reader.result as string);
          reader.readAsDataURL(file);
        };
        input.click();
        return;
      }

      // NATIVE LOGIC (Android/iOS)
      const permission = useCamera 
        ? await ImagePicker.requestCameraPermissionsAsync()
        : await ImagePicker.requestMediaLibraryPermissionsAsync();

      if (!permission.granted) {
        Alert.alert("Permission Required", "Please allow access to your camera/gallery in settings.");
        return;
      }

      const result = useCamera
        ? await ImagePicker.launchCameraAsync({ 
            base64: true, 
            quality: 0.7,
            allowsEditing: true,
            aspect: [1, 1] 
          })
        : await ImagePicker.launchImageLibraryAsync({ 
            base64: true, 
            quality: 0.7,
            allowsEditing: true,
            aspect: [1, 1]
          });

      if (!result.canceled && result.assets && result.assets[0].base64) {
        // Convert to data URI for consistency with the rest of the app
        onImageSelected(`data:image/jpeg;base64,${result.assets[0].base64}`);
      }
    } catch (error) {
      console.error("Picker Error:", error);
      Alert.alert("Error", "Something went wrong while picking the image.");
    }
  };

  return (
    <View style={styles.container}>
      <TouchableOpacity 
        style={styles.uploadBox} 
        onPress={() => handlePickImage(false)}
        activeOpacity={0.8}
      >
        <Text style={styles.icon}>📁</Text>
        <Text style={styles.boxTitle}>Gallery</Text>
        <Text style={styles.boxSub}>Pick a Photo</Text>
      </TouchableOpacity>

      <TouchableOpacity 
        style={styles.cameraBox} 
        onPress={() => handlePickImage(true)}
        activeOpacity={0.8}
      >
        <Text style={styles.icon}>📸</Text>
        <Text style={styles.boxTitle}>Camera</Text>
        <Text style={styles.boxSub}>Snap a Photo</Text>
      </TouchableOpacity>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flexDirection: 'row',
    gap: 15,
    width: '100%',
    paddingHorizontal: 5,
  },
  uploadBox: {
    flex: 1,
