import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { DesignStyle, ChatLink } from "../types";

const MODEL_IMAGE = 'gemini-2.5-flash-image';
const MODEL_CHAT = 'gemini-3-pro-preview';

export const generateReimaginedDesign = async (
  originalImageBase64: string,
  style: DesignStyle
): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `Act as a world-class interior designer. Reimagine this exact room into a high-end ${style} style. 
  Keep the architectural structure (windows, walls, doors) identical, but replace all furniture, flooring, lighting, and decor. 
  Focus on high-quality textures, realistic shadows, and professional interior photography aesthetics. 
  Style details: ${style} aesthetic, cohesive color palette, and premium materials.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: {
        parts: [
          {
            inlineData: {
              data: originalImageBase64.split(',')[1],
              mimeType: 'image/png'
            }
          },
          { text: prompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Error generating image:", error);
  }
  return null;
};

export const getDesignAdvice = async (
  userPrompt: string,
  imageBase64?: string
): Promise<{ text: string; links?: ChatLink[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const systemInstruction = `You are Lumina, a world-class Interior Design AI Consultant. 
  Analyze user spaces and provide actionable, professional advice.

  Key Responsibilities:
  1. Identify design styles and suggest improvements.
  2. Recommend specific furniture or decor items.
  3. Use Google Search to find real products and provide shoppable links.
  4. Always format your response using Markdown (bolding, headers, lists).

  Current Context: The user is looking at their reimagined room design. Provide specific product recommendations that would fit the aesthetic seen in the image.`;

  try {
    const parts: any[] = [{ text: userPrompt }];
    if (imageBase64) {
      parts.push({
        inlineData: {
          data: imageBase64.split(',')[1],
          mimeType: 'image/png'
        }
      });
    }

    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: { parts },
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
        temperature: 0.7,
      }
    });

    const text = response.text || "I'm sorry, I couldn't generate a response. Please try again.";

    const links: ChatLink[] = [];
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.web) {
          links.push({
            uri: chunk.web.uri,
            title: chunk.web.title
          });
        }
      });
    }

    return { text, links: links.length > 0 ? links : undefined };
  } catch (error) {
    console.error("Error in chat service:", error);
    return { text: "I'm having a bit of trouble connecting to my design brain. Please check your connection!" };
  }
};

