        style={styles.container}
      >
        <View style={styles.header}>
          <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
          {originalImage && (
            <TouchableOpacity onPress={handleReset} style={styles.resetBtn}>
              <Text style={styles.resetBtnText}>Reset</Text>
            </TouchableOpacity>
          )}
        </View>

        <ScrollView 
          style={styles.content}
          contentContainerStyle={styles.scrollContent}
          showsVerticalScrollIndicator={false}
        >
          {!originalImage ? (
            <View style={styles.welcomeContainer}>
              <View style={styles.heroSection}>
                <View style={styles.badge}>
                  <Text style={styles.badgeText}>GPT-4o & GEMINI POWERED</Text>
                </View>
                <Text style={styles.heroTitle}>Transform Your Living Space</Text>
                <Text style={styles.heroSubtitle}>Upload a photo of your room and watch AI reimagine it in seconds.</Text>
              </View>
              <ImageInput onImageSelected={handleImageInput} />
            </View>
          ) : (
            <View style={styles.studio}>
              <View style={styles.viewer}>
                {isGenerating && (
                  <View style={styles.loaderOverlay}>
                    <ActivityIndicator size="large" color="#4f46e5" />
                    <Text style={styles.loaderText}>Applying {selectedStyle} Style...</Text>
                  </View>
                )}
                <CompareSlider 
                  original={originalImage} 
                  modified={modifiedImage || originalImage} 
                />
              </View>

              <StyleCarousel 
                onSelect={handleStyleSelect} 
                selectedStyle={selectedStyle} 
                isGenerating={isGenerating} 
              />

              {modifiedImage && (
                <View style={styles.btnRow}>
                  <TouchableOpacity style={styles.saveBtn} onPress={handleSave}>
                    <Text style={styles.saveBtnText}>Save to Projects</Text>
                  </TouchableOpacity>
                </View>
              )}

              <View style={styles.chatSection}>
                <Text style={styles.sectionTitle}>Consult with Lumina</Text>
                <ChatInterface currentImage={modifiedImage || originalImage} />
              </View>
            </View>
          )}

          {savedDesigns.length > 0 && (
            <View style={styles.gallery}>
              <Text style={styles.sectionTitle}>Your Creations</Text>
              <ScrollView horizontal showsHorizontalScrollIndicator={false} style={styles.galleryScroll}>
                {savedDesigns.map(design => (
                  <View key={design.id} style={styles.galleryCard}>
                    <View style={styles.galleryImgWrap}>
                       <CompareSlider original={design.originalImage} modified={design.modifiedImage} />
                    </View>
                    <Text style={styles.galleryStyleLabel}>{design.style}</Text>
                  </View>
                ))}
              </ScrollView>
            </View>
          )}
        </ScrollView>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
};

