        temperature: 0.8,
      }
    });

    const text = response.text || "I'm processing your design request...";

    const links: ChatLink[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          links.push({
            uri: chunk.web.uri,
            title: chunk.web.title
          });
        }
      });
    }

    return { text, links: links.length > 0 ? links : undefined };
  } catch (error) {
    console.error("AI Chat Error:", error);
    return { text: "My design circuits are currently overwhelmed. Please try again in a second!" };
  }
};

