import { GoogleGenAI, Type } from "@google/genai";
import { DesignStyle, ChatLink } from "../types";

// Using the most capable models as per guidelines
const MODEL_IMAGE = 'gemini-3-pro-image-preview'; // Upgraded for better quality and reliability
const MODEL_CHAT = 'gemini-3-pro-preview';

const extractMimeType = (base64String: string): string => {
  const match = base64String.match(/^data:(image\/[a-zA-Z]+);base64,/);
  return match ? match[1] : 'image/jpeg';
};

const extractBase64Data = (base64String: string): string => {
  return base64String.includes(',') ? base64String.split(',')[1] : base64String;
};

export const generateReimaginedDesign = async (
  originalImageBase64: string,
  style: DesignStyle
): Promise<string | null> => {
  // Always create a new instance to get the latest key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

  const mimeType = extractMimeType(originalImageBase64);
  const base64Data = extractBase64Data(originalImageBase64);

  const prompt = `Professional Interior Design Transformation.
  Target Style: ${style}.
  Instruction: Redesign this room into a high-end ${style} space. 
  Keep the basic structural architecture (walls, windows) but replace all furniture, textures, and decor.
  Output: One high-quality photorealistic image of the redesigned room.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType
            }
          },
          { text: prompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "1K"
        }
      }
    });

    // Iterate parts to find the image as per guidelines
    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    console.warn("No image part found in AI response", response);
  } catch (error: any) {
    console.error("AI Generation Error Detail:", error);
    // Handle specific key error
    if (error.message?.includes("entity was not found")) {
      throw new Error("KEY_RESET_REQUIRED");
    }
    throw error;
  }
  return null;
};

export const getDesignAdvice = async (
  userPrompt: string,
  imageBase64?: string
): Promise<{ text: string; links?: ChatLink[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

  const systemInstruction = `You are Lumina, an elite AI Interior Design Consultant. 
  Recommend actual furniture pieces and use Google Search to find real products.
  Analyze images if provided. Use Markdown for formatting.`;

  try {
    const parts: any[] = [{ text: userPrompt }];
    if (imageBase64) {
      parts.push({
        inlineData: {
          data: extractBase64Data(imageBase64),
          mimeType: extractMimeType(imageBase64)
        }
      });
    }

    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: { parts },
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
      }
    });

    const text = response.text || "I'm analyzing your space...";
    const links: ChatLink[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          links.push({ uri: chunk.web.uri, title: chunk.web.title });
        }
      });
    }

    return { text, links: links.length > 0 ? links : undefined };
  } catch (error) {
    console.error("AI Chat Error:", error);
    return { text: "I'm having trouble connecting to my design database. Please try again." };
  }
};

