import React, { useState, useCallback } from 'react';
import { 
  StyleSheet, 
  View, 
  Image, 
  PanResponder, 
  Dimensions,
  Text 
} from 'react-native';

interface CompareSliderProps {
  original: string;
  modified: string;
}

const CompareSlider: React.FC<CompareSliderProps> = ({ original, modified }) => {
  const [sliderPos, setSliderPos] = useState(0.5);
  const [layoutWidth, setLayoutWidth] = useState(Dimensions.get('window').width - 40);

  const onLayout = (event: any) => {
    const { width } = event.nativeEvent.layout;
    if (width > 0) setLayoutWidth(width);
  };

  const handleMove = useCallback((evt: any) => {
    // Get X position relative to the container
    const touchX = evt.nativeEvent.locationX || (evt.nativeEvent.touches && evt.nativeEvent.touches[0].locationX);
    if (touchX !== undefined) {
      const newPos = Math.max(0, Math.min(1, touchX / layoutWidth));
      setSliderPos(newPos);
    }
  }, [layoutWidth]);

  const panResponder = PanResponder.create({
    onStartShouldSetPanResponder: () => true,
    onMoveShouldSetPanResponder: () => true,
    onPanResponderMove: (evt, gestureState) => {
      // Use dx and absolute position for smoother experience
      const touchX = gestureState.moveX - (Dimensions.get('window').width - layoutWidth) / 2;
      const newPos = Math.max(0, Math.min(1, touchX / layoutWidth));
      setSliderPos(newPos);
    },
  });

  return (
    <View style={styles.container} onLayout={onLayout} {...panResponder.panHandlers}>
      {/* Background (Modified) */}
      <Image source={{ uri: modified }} style={styles.fullImage} />

      {/* Clipped Original Image */}
      <View style={[styles.clippedContainer, { width: `${sliderPos * 100}%` }]}>
        <Image 
          source={{ uri: original }} 
          style={[styles.fullImage, { width: layoutWidth }]} 
        />
      </View>

      {/* Slider Line & Handle */}
      <View style={[styles.sliderLine, { left: `${sliderPos * 100}%` }]}>
        <View style={styles.handle}>
          <Text style={styles.handleText}>↔</Text>
        </View>
      </View>

      <View style={styles.labelBefore}>
        <Text style={styles.labelText}>ORIGINAL</Text>
      </View>
      <View style={styles.labelAfter}>
        <Text style={styles.labelText}>REIMAGINED</Text>
      </View>
    </View>
  );
};

