  }
}

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [needsKey, setNeedsKey] = useState(false);

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async () => {
    if (Platform.OS === 'web' && window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        setNeedsKey(true);
      }
    }
  };

  const handleOpenKeyPicker = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setNeedsKey(false);
    }
  };

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage || isGenerating) return;

    setSelectedStyle(style);
    setIsGenerating(true);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      } else {
        Alert.alert("Design Failed", "The AI couldn't generate a design. Try again with a clearer photo.");
      }
    } catch (e: any) {
      console.error(e);
      if (e.message === "KEY_RESET_REQUIRED") {
        Alert.alert("API Key Issue", "Your API key session expired or is invalid. Please select it again.", [
          { text: "Select Key", onPress: handleOpenKeyPicker }
        ]);
      } else {
        Alert.alert("Error", "Something went wrong. Please check your internet connection.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  if (needsKey) {
    return (
      <SafeAreaView style={styles.safeArea}>
        <View style={styles.centerContainer}>
          <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
          <Text style={styles.setupTitle}>Ready to Reimagining?</Text>
