// Fix: Removed the separate AIStudio interface definition and updated the global Window augmentation
// to use an anonymous type structure. This prevents "Subsequent property declarations must have the same type" 
// errors that occur when the name "AIStudio" might already be defined in the global namespace or in other modules.
declare global {
  interface Window {
    aistudio?: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [needsKey, setNeedsKey] = useState(false);

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async () => {
    if (Platform.OS === 'web' && window.aistudio) {
      try {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
          setNeedsKey(true);
        }
      } catch (e) {
        console.error("Error checking API key:", e);
      }
    }
  };

  const handleOpenKeyPicker = async () => {
    if (window.aistudio) {
      try {
        await window.aistudio.openSelectKey();
        // Proceeding immediately after triggering the dialog to mitigate race conditions
        setNeedsKey(false);
      } catch (e) {
        console.error("Error opening key picker:", e);
      }
    }
  };

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage || isGenerating) return;

    setSelectedStyle(style);
    setIsGenerating(true);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      } else {
        Alert.alert("Design Failed", "The AI model returned an empty response. This can happen with very dark or blurry photos.");
      }
    } catch (e: any) {
      console.error("Generation Error:", e);
      if (e.message === "KEY_RESET_REQUIRED" || (e.message && e.message.includes("entity was not found"))) {
        setNeedsKey(true);
        Alert.alert("API Key Required", "Please select a valid Paid Project API key to use the redesign feature.", [
          { text: "Select Key", onPress: handleOpenKeyPicker }
        ]);
      } else {
        Alert.alert("AI Error", "The model is currently busy or the request failed. Please try again in a moment.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  if (needsKey) {
    return (
