import { GoogleGenAI, Type } from "@google/genai";
import { DesignStyle, ChatLink } from "../types";

// Using models that offer the best balance of quality and accessibility
const MODEL_IMAGE = 'gemini-2.5-flash-image'; 
const MODEL_CHAT = 'gemini-3-flash-preview';

const extractMimeType = (base64String: string): string => {
  const match = base64String.match(/^data:(image\/[a-zA-Z]+);base64,/);
  return match ? match[1] : 'image/jpeg';
};

const extractBase64Data = (base64String: string): string => {
  return base64String.includes(',') ? base64String.split(',')[1] : base64String;
};

export const generateReimaginedDesign = async (
  originalImageBase64: string,
  style: DesignStyle
): Promise<string | null> => {
  // Always create a new instance to get the latest key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

  const mimeType = extractMimeType(originalImageBase64);
  const base64Data = extractBase64Data(originalImageBase64);

  const prompt = `Professional Interior Design Transformation.
  Target Style: ${style}.
  Instruction: Redesign this room into a high-end ${style} space. 
  Keep the basic structural architecture like walls, windows, and floors exactly where they are. 
  Replace all furniture, lighting, and decor items with pieces that strictly follow the ${style} aesthetic.
  Ensure lighting is realistic and the result looks like a professional photograph.
  Output: One photorealistic image.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType
            }
          },
          { text: prompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image was returned by the AI. Try a different style.");
  } catch (error: any) {
    console.error("AI Generation Error:", error);
    // Propagate the actual error message for UI display
    if (error.message?.includes("entity was not found") || error.message?.includes("404")) {
      throw new Error("MODEL_ACCESS_ERROR");
    }
    throw error;
  }
};

export const getDesignAdvice = async (
  userPrompt: string,
  imageBase64?: string
): Promise<{ text: string; links?: ChatLink[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

  const systemInstruction = `You are Lumina, an elite AI Interior Design Consultant. 
  Your goal is to provide specific, actionable design advice. 
  If an image is provided, analyze the furniture and layout carefully.
  Use Google Search to suggest real, currently available furniture styles and brands.
  Keep responses elegant, helpful, and concise. Use Markdown for lists.`;

  try {
    const parts: any[] = [{ text: userPrompt }];
    if (imageBase64) {
      parts.push({
        inlineData: {
          data: extractBase64Data(imageBase64),
          mimeType: extractMimeType(imageBase64)
        }
      });
    }

    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: { parts },
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
      }
    });

    const text = response.text || "I'm having trouble thinking of advice right now.";
    const links: ChatLink[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          links.push({ uri: chunk.web.uri, title: chunk.web.title });
        }
      });
    }

    return { text, links: links.length > 0 ? links : undefined };
  } catch (error) {
    console.error("AI Chat Error:", error);
    return { text: "I'm having trouble connecting to the design database. Please try again." };
  }
};

