// Fix: Define the AIStudio interface and use it to augment the global Window object
// to match existing ambient declarations and fix the type mismatch error.
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    aistudio: AIStudio;
  }
}

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [needsKey, setNeedsKey] = useState(false);

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async () => {
    if (Platform.OS === 'web' && window.aistudio) {
      try {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
          setNeedsKey(true);
        }
      } catch (e) {
        console.error("Error checking API key:", e);
      }
    }
  };

  const handleOpenKeyPicker = async () => {
    if (window.aistudio) {
      try {
        await window.aistudio.openSelectKey();
        setNeedsKey(false);
      } catch (e) {
        console.error("Error opening key picker:", e);
      }
    }
  };

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage || isGenerating) return;

    setSelectedStyle(style);
    setIsGenerating(true);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      } else {
        throw new Error("No result returned.");
      }
    } catch (e: any) {
      console.error("Generation Error Flow:", e);
      if (e.message === "MODEL_ACCESS_ERROR") {
        Alert.alert(
          "Access Error", 
          "The AI model is not accessible. This usually means you need to select a Paid Project API key in the connection dialog.",
          [{ text: "Reconnect", onPress: handleOpenKeyPicker }, { text: "Cancel" }]
        );
      } else if (e.message?.includes("quota")) {
        Alert.alert("Quota Exceeded", "You've reached the free limit for this model. Please wait a minute or use a paid key.");
      } else {
        Alert.alert("Design Failed", e.message || "Something went wrong with the AI generation.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  if (needsKey) {
    return (
      <SafeAreaView style={styles.safeArea}>
        <View style={styles.centerContainer}>
          <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
          <View style={styles.setupCard}>
            <Text style={styles.setupTitle}>Connect to Gemini</Text>
            <Text style={styles.setupSub}>To use high-quality interior design AI, please select your Google AI Studio API key.</Text>
            <TouchableOpacity style={styles.primaryBtn} onPress={handleOpenKeyPicker}>
              <Text style={styles.primaryBtnText}>Connect API Key</Text>
            </TouchableOpacity>
            <TouchableOpacity onPress={() => Linking.openURL('https://ai.google.dev/gemini-api/docs/billing')}>
              <Text style={styles.linkText}>Billing & Key Info ↗</Text>
            </TouchableOpacity>
          </View>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.safeArea}>
      <StatusBar barStyle="dark-content" />
      <KeyboardAvoidingView 
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
        style={styles.container}
      >
        <View style={styles.header}>
          <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
          {originalImage && (
            <TouchableOpacity onPress={() => setOriginalImage(null)} style={styles.resetBtn}>
              <Text style={styles.resetBtnText}>New Project</Text>
            </TouchableOpacity>
          )}
        </View>

        <ScrollView style={styles.content} contentContainerStyle={styles.scrollContent}>
          {!originalImage ? (
            <View style={styles.welcomeContainer}>
              <View style={styles.heroSection}>
                <View style={styles.badge}><Text style={styles.badgeText}>FLASH 2.5 AI</Text></View>
                <Text style={styles.heroTitle}>Reimagine Your Living Space</Text>
                <Text style={styles.heroSubtitle}>Instant interior transformations powered by Google Gemini.</Text>
              </View>
              <ImageInput onImageSelected={handleImageInput} />
            </View>
          ) : (
            <View style={styles.studio}>
              <View style={styles.viewer}>
                {isGenerating && (
                  <View style={styles.loaderOverlay}>
                    <ActivityIndicator size="large" color="#4f46e5" />
                    <Text style={styles.loaderText}>Reimagining in {selectedStyle} style...</Text>
                    <Text style={styles.loaderSubText}>This typically takes 5-10 seconds</Text>
                  </View>
                )}
                <CompareSlider 
                  original={originalImage} 
                  modified={modifiedImage || originalImage} 
                />
              </View>

              <StyleCarousel 
                onSelect={handleStyleSelect} 
                selectedStyle={selectedStyle} 
                isGenerating={isGenerating} 
              />

              <View style={styles.chatSection}>
                <Text style={styles.sectionTitle}>Ask for Design Advice</Text>
                <ChatInterface currentImage={modifiedImage || originalImage} onEditRequested={() => {}} />
              </View>
            </View>
