import { GoogleGenAI } from "@google/genai";
import { DesignStyle, ChatLink } from "../types";

// Using models that offer the best balance of quality and accessibility
const MODEL_IMAGE = 'gemini-2.5-flash-image'; 
const MODEL_CHAT = 'gemini-3-flash-preview';

const extractMimeType = (base64String: string): string => {
  const match = base64String.match(/^data:(image\/[a-zA-Z]+);base64,/);
  return match ? match[1] : 'image/jpeg';
};

const extractBase64Data = (base64String: string): string => {
  if (base64String.includes(',')) {
    return base64String.split(',')[1];
  }
  return base64String;
};

export const generateReimaginedDesign = async (
  originalImageBase64: string,
  style: DesignStyle
): Promise<string | null> => {
  console.log(`[Lumina] Starting redesign for style: ${style}`);

  // Create a new instance right before use to ensure latest API key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

  const mimeType = extractMimeType(originalImageBase64);
  const base64Data = extractBase64Data(originalImageBase64);

  const prompt = `Act as a world-class interior designer. 
  Redesign this room completely in the ${style} style. 
  Keep the room's layout, walls, and windows exactly the same.
  Replace all furniture, rugs, wall art, and lighting with high-end ${style} pieces.
  The final result must be a photorealistic, professional architectural photograph.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType
            }
          },
          { text: prompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    if (!response.candidates?.[0]?.content?.parts) {
      console.error("[Lumina] Empty response parts from model");
      throw new Error("EMPTY_RESPONSE");
    }

    // Iterate through parts to find the image, as the model may return text too
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        console.log("[Lumina] Successfully generated new design image");
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("NO_IMAGE_PART");
  } catch (error: any) {
    console.error("[Lumina] API Error:", error);

    // Check for specific error types
    const errorMsg = error.message || "";
    if (errorMsg.includes("entity was not found") || errorMsg.includes("404")) {
      throw new Error("MODEL_NOT_FOUND");
    } else if (errorMsg.includes("quota") || errorMsg.includes("429")) {
      throw new Error("RATE_LIMIT");
    }

    throw error;
  }
};

export const getDesignAdvice = async (
  userPrompt: string,
  imageBase64?: string
): Promise<{ text: string; links?: ChatLink[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

  const systemInstruction = `You are Lumina, a helpful AI interior designer. 
  Answer questions about furniture, color palettes, and decor. 
  Be specific and use Markdown for formatting.`;

  try {
    const parts: any[] = [{ text: userPrompt }];
    if (imageBase64) {
      parts.push({
        inlineData: {
          data: extractBase64Data(imageBase64),
          mimeType: extractMimeType(imageBase64)
        }
      });
    }

    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: { parts },
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
      }
    });

    const text = response.text || "I'm sorry, I couldn't process that request.";
    const links: ChatLink[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          links.push({ uri: chunk.web.uri, title: chunk.web.title });
        }
      });
    }

    return { text, links: links.length > 0 ? links : undefined };
  } catch (error) {
    console.error("[Lumina] Chat Error:", error);
    return { text: "I'm having trouble connecting right now. Please try again later." };
  }
};

