declare global {
  interface AIStudio {
    hasSelectedApiKey(): Promise<boolean>;
    openSelectKey(): Promise<void>;
  }

  interface Window {
    readonly aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [apiStatus, setApiStatus] = useState<'checking' | 'connected' | 'error'>('checking');

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async () => {
    setApiStatus('checking');
    if (Platform.OS === 'web' && window.aistudio) {
      try {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
          setNeedsKey(true);
          setApiStatus('error');
        } else {
          // Double verify if the key actually works
          const isWorking = await testConnection();
          setApiStatus(isWorking ? 'connected' : 'error');
          if (!isWorking) setNeedsKey(true);
        }
      } catch (e) {
        console.error("Error checking API key:", e);
        setApiStatus('error');
      }
    }
  };

  const handleOpenKeyPicker = async () => {
    if (window.aistudio) {
      try {
        await window.aistudio.openSelectKey();
        setNeedsKey(false);
        // Retry verification after user interaction
        setTimeout(checkApiKey, 500);
      } catch (e) {
        console.error("Error opening key picker:", e);
      }
    }
  };

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage) {
      Alert.alert("No Photo", "Please upload a photo of your room first.");
      return;
    }

    if (!process.env.API_KEY) {
      Alert.alert("API Key Missing", "Your API key is not active. Please reconnect.", [
        { text: "Reconnect", onPress: handleOpenKeyPicker }
      ]);
      setNeedsKey(true);
      return;
    }

    if (isGenerating) return;

    setSelectedStyle(style);
    setIsGenerating(true);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      } else {
        throw new Error("NO_RESULT");
      }
    } catch (e: any) {
      console.error("[App] Generation Failed:", e);

      let errorTitle = "Design Failed";
      let errorMsg = "Something went wrong. This often happens if the API key is invalid or has no credits.";

      if (e.message?.includes("403") || e.message?.includes("401") || e.message === "API_KEY_MISSING") {
        errorTitle = "API Error";
        errorMsg = "Your API key is invalid or expired. Please select a fresh key from a Paid Project.";
        Alert.alert(errorTitle, errorMsg, [{ text: "Reconnect", onPress: handleOpenKeyPicker }]);
      } else {
        Alert.alert(errorTitle, errorMsg + "\n\nError: " + (e.message || "Unknown"));
      }
      setSelectedStyle(null);
    } finally {
      setIsGenerating(false);
    }
  };

  if (needsKey) {
    return (
      <SafeAreaView style={styles.safeArea}>
        <View style={styles.centerContainer}>
          <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
          <View style={styles.setupCard}>
