            <Text style={styles.setupSub}>To transform your space, you must connect a Google AI Studio API key (Paid Project).</Text>
            <TouchableOpacity style={styles.primaryBtn} onPress={handleOpenKeyPicker}>
              <Text style={styles.primaryBtnText}>Connect API Key</Text>
            </TouchableOpacity>
            <TouchableOpacity onPress={() => Linking.openURL('https://ai.google.dev/gemini-api/docs/billing')}>
              <Text style={styles.linkText}>Billing & Quota Info ↗</Text>
            </TouchableOpacity>
          </View>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.safeArea}>
      <StatusBar barStyle="dark-content" />
      <KeyboardAvoidingView 
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
        style={styles.container}
      >
        <View style={styles.header}>
          <View>
            <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
            <View style={styles.apiStatusRow}>
              <View style={[styles.statusDot, { backgroundColor: apiStatus === 'connected' ? '#22c55e' : apiStatus === 'checking' ? '#eab308' : '#ef4444' }]} />
              <Text style={styles.statusText}>
                {apiStatus === 'connected' ? 'API Connected' : apiStatus === 'checking' ? 'Checking API...' : 'API Error'}
              </Text>
            </View>
          </View>
          {originalImage && (
            <TouchableOpacity onPress={() => setOriginalImage(null)} style={styles.resetBtn}>
              <Text style={styles.resetBtnText}>New</Text>
            </TouchableOpacity>
          )}
        </View>

        <ScrollView style={styles.content} contentContainerStyle={styles.scrollContent}>
          {!originalImage ? (
            <View style={styles.welcomeContainer}>
              <View style={styles.heroSection}>
                <View style={styles.badge}><Text style={styles.badgeText}>ELITE INTERIOR AI</Text></View>
                <Text style={styles.heroTitle}>Your Personal Interior Designer</Text>
                <Text style={styles.heroSubtitle}>Instant professional room makeovers at your fingertips.</Text>
              </View>
              <ImageInput onImageSelected={handleImageInput} />
            </View>
          ) : (
            <View style={styles.studio}>
              <View style={styles.viewer}>
                {isGenerating && (
                  <View style={styles.loaderOverlay}>
                    <ActivityIndicator size="large" color="#4f46e5" />
                    <Text style={styles.loaderText}>Processing {selectedStyle}...</Text>
                    <Text style={styles.loaderSubText}>Crafting architectural quality details</Text>
