import { GoogleGenAI } from "@google/genai";
import { DesignStyle, ChatLink } from "../types";

// Using models that offer the best balance of quality and accessibility
const MODEL_IMAGE = 'gemini-2.5-flash-image'; 
const MODEL_CHAT = 'gemini-3-flash-preview';

const extractMimeType = (base64String: string): string => {
  const match = base64String.match(/^data:(image\/[a-zA-Z]+);base64,/);
  return match ? match[1] : 'image/jpeg';
};

const extractBase64Data = (base64String: string): string => {
  if (base64String.includes(',')) {
    return base64String.split(',')[1];
  }
  return base64String;
};

export const testConnection = async (): Promise<{ success: boolean; error?: string }> => {
  const key = process.env.API_KEY;
  console.log("[Lumina-API] Starting connection test...");

  if (!key || key.length < 10) {
    console.error("[Lumina-API] API Key is missing or too short.");
    return { success: false, error: 'Key Missing' };
  }

  try {
    const ai = new GoogleGenAI({ apiKey: key });
    // Minimal call to check if key is valid and has permissions
    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: "Connection test. Respond with 'ok'.",
      config: { maxOutputTokens: 5 }
    });

    if (response.text) {
      console.log("[Lumina-API] Connection verified successfully.");
      return { success: true };
    }
    return { success: false, error: 'Empty Response' };
  } catch (error: any) {
    console.error("[Lumina-API] Test failed:", error.message);
    return { success: false, error: error.message };
  }
};

export const generateReimaginedDesign = async (
  originalImageBase64: string,
  style: DesignStyle
): Promise<string | null> => {
  console.log(`[Lumina-API] Reimagining room as: ${style}`);

  const key = process.env.API_KEY;
  if (!key) throw new Error("API_KEY_MISSING");

  const ai = new GoogleGenAI({ apiKey: key });
  const mimeType = extractMimeType(originalImageBase64);
  const base64Data = extractBase64Data(originalImageBase64);

  const prompt = `Act as a professional interior designer. Completely transform this room into a high-end ${style} space. Keep the architectural structure (walls, windows, layout) but replace all furniture, textures, and lighting. Output must be a photorealistic image.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: prompt }
        ]
      },
      config: { 
        imageConfig: { aspectRatio: "1:1" }
      }
    });

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          console.log("[Lumina-API] Image generated successfully.");
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
    throw new Error("MODEL_DID_NOT_RETURN_IMAGE");
  } catch (error: any) {
    console.error("[Lumina-API] Generation Error:", error);
    throw error;
  }
};

export const getDesignAdvice = async (
  userPrompt: string,
  imageBase64?: string
): Promise<{ text: string; links?: ChatLink[] }> => {
  const key = process.env.API_KEY;
  if (!key) return { text: "Please connect your API key first." };

  const ai = new GoogleGenAI({ apiKey: key });
  const systemInstruction = `You are Lumina, a world-class AI interior design consultant. Use professional, encouraging language. Provide specific furniture and decor suggestions. Use Markdown formatting.`;

  try {
    const parts: any[] = [{ text: userPrompt }];
    if (imageBase64) {
      parts.push({
        inlineData: {
          data: extractBase64Data(imageBase64),
          mimeType: extractMimeType(imageBase64)
        }
      });
    }

    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: { parts },
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
      }
    });

    const text = response.text || "I'm sorry, I couldn't process that request.";
    const links: ChatLink[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          links.push({ uri: chunk.web.uri, title: chunk.web.title });
        }
      });
    }

    return { text, links: links.length > 0 ? links : undefined };
  } catch (error) {
    console.error("[Lumina-API] Chat Error:", error);
    return { text: "The design consultant is currently offline. Please check your connection." };
  }
};

import React, { useState, useEffect } from 'react';
import { 
  StyleSheet, 
  View, 
  Text, 
  ScrollView, 
  SafeAreaView, 
  TouchableOpacity, 
  Alert,
  ActivityIndicator,
  StatusBar,
  Platform,
  KeyboardAvoidingView,
  Linking
} from 'react-native';
import ImageInput from './components/ImageInput';
import StyleCarousel from './components/StyleCarousel';
import CompareSlider from './components/CompareSlider';
import ChatInterface from './components/ChatInterface';
import { DesignStyle } from './types';
import { generateReimaginedDesign, testConnection } from './services/geminiService';

declare global {
  interface AIStudio {
    hasSelectedApiKey(): Promise<boolean>;
    openSelectKey(): Promise<void>;
  }

  interface Window {
    readonly aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [apiStatus, setApiStatus] = useState<'checking' | 'connected' | 'error'>('checking');

  useEffect(() => {
    initialCheck();
  }, []);

  const initialCheck = async () => {
    setApiStatus('checking');

    // 1. Check if we're in an AI Studio environment
    if (Platform.OS === 'web' && window.aistudio) {
      try {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
          setNeedsKey(true);
          setApiStatus('error');
          return;
        }
      } catch (e) {
        console.warn("AI Studio key check failed, falling back to process.env");
      }
    }

    // 2. Perform actual functional test
    await performApiTest();
  };

  const performApiTest = async () => {
    const result = await testConnection();
    if (result.success) {
      setApiStatus('connected');
      setNeedsKey(false);
    } else {
      setApiStatus('error');
      // Only show the blocking key screen if we're in the AI Studio environment
      if (window.aistudio) setNeedsKey(true);
    }
  };

  const handleOpenKeyPicker = async () => {
    if (window.aistudio) {
      try {
        await window.aistudio.openSelectKey();
        setNeedsKey(false);
        // Small delay to allow environment to update
        setTimeout(performApiTest, 800);
      } catch (e) {
        console.error("Error opening key picker:", e);
      }
    }
  };

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage) {
      Alert.alert("Step 1", "Please upload a photo of your room first!");
      return;
    }

    if (apiStatus !== 'connected') {
      Alert.alert("Connection Issue", "API is not connected. Would you like to re-test?", [
        { text: "Retry", onPress: performApiTest },
        { text: "Select Key", onPress: handleOpenKeyPicker },
        { text: "Cancel", style: "cancel" }
      ]);
      return;
    }

    if (isGenerating) return;

    setSelectedStyle(style);
    setIsGenerating(true);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      } else {
        throw new Error("NO_RESULT");
      }
    } catch (e: any) {
      console.error("[App] Style Application Failed:", e);

      let errorTitle = "Design Error";
      let errorMsg = "The AI couldn't process this request. This usually happens if the API key is restricted or the prompt was blocked.";

      if (e.message?.includes("403") || e.message?.includes("401")) {
        errorTitle = "Authentication Failed";
        errorMsg = "Your API key is invalid. Please select a fresh key from a Paid Project.";
        setApiStatus('error');
      }

      Alert.alert(errorTitle, errorMsg);
      setSelectedStyle(null);
    } finally {
      setIsGenerating(false);
    }
  };

  if (needsKey && window.aistudio) {
    return (
      <SafeAreaView style={styles.safeArea}>
        <View style={styles.centerContainer}>
          <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
          <View style={styles.setupCard}>
            <Text style={styles.setupTitle}>Setup Required</Text>
            <Text style={styles.setupSub}>To access professional AI design features, please connect your API key.</Text>
            <TouchableOpacity style={styles.primaryBtn} onPress={handleOpenKeyPicker}>
              <Text style={styles.primaryBtnText}>Connect API Key</Text>
            </TouchableOpacity>
            <TouchableOpacity onPress={() => Linking.openURL('https://ai.google.dev/gemini-api/docs/billing')} style={styles.linkContainer}>
              <Text style={styles.linkText}>Learn about billing & quota ↗</Text>
            </TouchableOpacity>
          </View>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.safeArea}>
      <StatusBar barStyle="dark-content" />
      <KeyboardAvoidingView 
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
        style={styles.container}
      >
        <View style={styles.header}>
          <TouchableOpacity onPress={performApiTest} activeOpacity={0.7}>
            <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
            <View style={styles.apiStatusRow}>
              <View style={[styles.statusDot, { backgroundColor: apiStatus === 'connected' ? '#22c55e' : apiStatus === 'checking' ? '#eab308' : '#ef4444' }]} />
              <Text style={styles.statusText}>
                {apiStatus === 'connected' ? 'API Active' : apiStatus === 'checking' ? 'Syncing...' : 'API Down'}
              </Text>
            </View>
          </TouchableOpacity>
          {originalImage && (
            <TouchableOpacity onPress={() => setOriginalImage(null)} style={styles.resetBtn}>
              <Text style={styles.resetBtnText}>New Room</Text>
            </TouchableOpacity>
          )}
        </View>

        <ScrollView style={styles.content} contentContainerStyle={styles.scrollContent} showsVerticalScrollIndicator={false}>
          {!originalImage ? (
            <View style={styles.welcomeContainer}>
              <View style={styles.heroSection}>
                <View style={styles.badge}><Text style={styles.badgeText}>ELITE INTERIOR AI</Text></View>
                <Text style={styles.heroTitle}>Redesign Your Home in Seconds</Text>
                <Text style={styles.heroSubtitle}>Upload a photo of any room and watch our AI transform it with professional precision.</Text>
              </View>
              <ImageInput onImageSelected={handleImageInput} />
            </View>
          ) : (
            <View style={styles.studio}>
              <View style={styles.viewer}>
                {isGenerating && (
                  <View style={styles.loaderOverlay}>
                    <ActivityIndicator size="large" color="#4f46e5" />
                    <Text style={styles.loaderText}>Styling: {selectedStyle}</Text>
                    <Text style={styles.loaderSubText}>Applying architectural lighting and furniture...</Text>
                  </View>
                )}
                <CompareSlider 
                  original={originalImage} 
                  modified={modifiedImage || originalImage} 
                />
              </View>

              <StyleCarousel 
                onSelect={handleStyleSelect} 
                selectedStyle={selectedStyle} 
                isGenerating={isGenerating} 
              />

              <View style={styles.chatSection}>
                <Text style={styles.sectionTitle}>Refine & Shop</Text>
                <ChatInterface currentImage={modifiedImage || originalImage} onEditRequested={() => {}} />
              </View>
            </View>
          )}
        </ScrollView>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
};

