        if (part.inlineData) {
          console.log("[Lumina-API] Image generated successfully.");
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
    throw new Error("MODEL_DID_NOT_RETURN_IMAGE");
  } catch (error: any) {
    console.error("[Lumina-API] Generation Error:", error);
    throw error;
  }
};

// Provides design advice with search grounding for real-time furniture suggestions
export const getDesignAdvice = async (
  userPrompt: string,
  imageBase64?: string
): Promise<{ text: string; links?: ChatLink[] }> => {
  const key = process.env.API_KEY;
  if (!key) return { text: "Please connect your API key first." };

  // Create new instance right before making an API call
  const ai = new GoogleGenAI({ apiKey: key });
  const systemInstruction = `You are Lumina, a world-class AI interior design consultant. Use professional, encouraging language. Provide specific furniture and decor suggestions. Use Markdown formatting.`;

  try {
    const parts: any[] = [{ text: userPrompt }];
    if (imageBase64) {
      parts.push({
        inlineData: {
          data: extractBase64Data(imageBase64),
          mimeType: extractMimeType(imageBase64)
        }
      });
    }

    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: { parts },
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
      }
    });

    const text = response.text || "I'm sorry, I couldn't process that request.";
    const links: ChatLink[] = [];
    // Always extract website URLs from groundingChunks to display references
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          links.push({ uri: chunk.web.uri, title: chunk.web.title });
        }
      });
    }

    return { text, links: links.length > 0 ? links : undefined };
  } catch (error) {
    console.error("[Lumina-API] Chat Error:", error);
    return { text: "The design consultant is currently offline. Please check your connection." };
  }
};

import React, { useState, useEffect } from 'react';
