const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [apiStatus, setApiStatus] = useState<'checking' | 'connected' | 'error'>('checking');

  useEffect(() => {
    initialCheck();
  }, []);

  // Helper to safely access AI Studio API in a web environment without type conflicts
  const getAiStudio = () => {
    if (typeof window !== 'undefined' && (window as any).aistudio) {
      return (window as any).aistudio;
    }
    return null;
  };

  // Initial check for API key status in the hosting environment
  const initialCheck = async () => {
    setApiStatus('checking');

    const aistudio = getAiStudio();
    if (Platform.OS === 'web' && aistudio) {
      try {
        const hasKey = await aistudio.hasSelectedApiKey();
        if (!hasKey) {
          setNeedsKey(true);
          setApiStatus('error');
          return;
        }
      } catch (e) {
        console.warn("AI Studio key check failed, falling back to process.env");
      }
    }

    await performApiTest();
  };

  // Functional verification of the API key
  const performApiTest = async () => {
    const result = await testConnection();
    if (result.success) {
      setApiStatus('connected');
      setNeedsKey(false);
    } else {
      setApiStatus('error');

      // If entity not found, the selected key might be invalid for the model/region
      if (result.error?.includes("Requested entity was not found.")) {
        const aistudio = getAiStudio();
        if (aistudio) {
          aistudio.openSelectKey();
          setNeedsKey(true);
          return;
        }
      }

      // Show setup screen if in AI Studio
      if (getAiStudio()) setNeedsKey(true);
    }
  };

  // Opens the API key selection dialog provided by AI Studio
  const handleOpenKeyPicker = async () => {
    const aistudio = getAiStudio();
    if (aistudio) {
      try {
        await aistudio.openSelectKey();
        setNeedsKey(false);
        // Assume the key selection was successful and proceed immediately to mitigate race conditions
        performApiTest();
      } catch (e) {
        console.error("Error opening key picker:", e);
      }
    }
  };

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage) {
      Alert.alert("Step 1", "Please upload a photo of your room first!");
      return;
    }

    if (apiStatus !== 'connected') {
      Alert.alert("Connection Issue", "API is not connected. Would you like to re-test?", [
        { text: "Retry", onPress: performApiTest },
        { text: "Select Key", onPress: handleOpenKeyPicker },
        { text: "Cancel", style: "cancel" }
      ]);
      return;
    }

    if (isGenerating) return;

    setSelectedStyle(style);
    setIsGenerating(true);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      } else {
        throw new Error("NO_RESULT");
      }
    } catch (e: any) {
      console.error("[App] Style Application Failed:", e);

      // If entity not found error occurs, prompt user to select a valid paid key
      if (e.message?.includes("Requested entity was not found.")) {
        setApiStatus('error');
        setNeedsKey(true);
        const aistudio = getAiStudio();
        if (aistudio) aistudio.openSelectKey();
        return;
      }

      let errorTitle = "Design Error";
      let errorMsg = "The AI couldn't process this request. This usually happens if the API key is restricted or the prompt was blocked.";

      if (e.message?.includes("403") || e.message?.includes("401")) {
        errorTitle = "Authentication Failed";
        errorMsg = "Your API key is invalid. Please select a fresh key from a Paid Project.";
        setApiStatus('error');
      }

      Alert.alert(errorTitle, errorMsg);
      setSelectedStyle(null);
    } finally {
      setIsGenerating(false);
    }
  };

