      <SafeAreaView style={styles.safeArea}>
        <View style={styles.centerContainer}>
          <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
          <View style={styles.setupCard}>
            <Text style={styles.setupTitle}>Setup Required</Text>
            <Text style={styles.setupSub}>To access professional AI design features, please connect your API key.</Text>
            <TouchableOpacity style={styles.primaryBtn} onPress={handleOpenKeyPicker}>
              <Text style={styles.primaryBtnText}>Connect API Key</Text>
            </TouchableOpacity>
            <TouchableOpacity onPress={() => Linking.openURL('https://ai.google.dev/gemini-api/docs/billing')} style={styles.linkContainer}>
              <Text style={styles.linkText}>Learn about billing & quota ↗</Text>
            </TouchableOpacity>
          </View>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.safeArea}>
      <StatusBar barStyle="dark-content" />
      <KeyboardAvoidingView 
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
        style={styles.container}
      >
        <View style={styles.header}>
          <TouchableOpacity onPress={performApiTest} activeOpacity={0.7}>
            <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
            <View style={styles.apiStatusRow}>
              <div style={{...styles.statusDot, backgroundColor: apiStatus === 'connected' ? '#22c55e' : apiStatus === 'checking' ? '#eab308' : '#ef4444' }} />
              <Text style={styles.statusText}>
                {apiStatus === 'connected' ? 'API Active' : apiStatus === 'checking' ? 'Syncing...' : 'API Down'}
              </Text>
            </View>
          </TouchableOpacity>
          {originalImage && (
            <TouchableOpacity onPress={() => setOriginalImage(null)} style={styles.resetBtn}>
              <Text style={styles.resetBtnText}>New Room</Text>
            </TouchableOpacity>
          )}
        </View>

        <ScrollView style={styles.content} contentContainerStyle={styles.scrollContent} showsVerticalScrollIndicator={false}>
          {!originalImage ? (
            <View style={styles.welcomeContainer}>
              <View style={styles.heroSection}>
                <View style={styles.badge}><Text style={styles.badgeText}>ELITE INTERIOR AI</Text></View>
                <Text style={styles.heroTitle}>Redesign Your Home in Seconds</Text>
                <Text style={styles.heroSubtitle}>Upload a photo of any room and watch our AI transform it with professional precision.</Text>
              </View>
              <ImageInput onImageSelected={handleImageInput} />
            </View>
          ) : (
            <View style={styles.studio}>
              <View style={styles.viewer}>
                {isGenerating && (
                  <View style={styles.loaderOverlay}>
                    <ActivityIndicator size="large" color="#4f46e5" />
                    <Text style={styles.loaderText}>Styling: {selectedStyle}</Text>
                    <Text style={styles.loaderSubText}>Applying architectural lighting and furniture...</Text>
                  </View>
                )}
                <CompareSlider 
                  original={originalImage} 
                  modified={modifiedImage || originalImage} 
                />
              </View>

              <StyleCarousel 
                onSelect={handleStyleSelect} 
                selectedStyle={selectedStyle} 
                isGenerating={isGenerating} 
              />

              <View style={styles.chatSection}>
                <Text style={styles.sectionTitle}>Refine & Shop</Text>
                <ChatInterface currentImage={modifiedImage || originalImage} onEditRequested={() => {}} />
