import { GoogleGenAI } from "@google/genai";
import { DesignStyle, ChatLink } from "../types";

// Using the most stable and widely available models for maximum reliability
const MODEL_IMAGE = 'gemini-2.5-flash-image'; 
const MODEL_CHAT = 'gemini-3-flash-preview';

const extractMimeType = (base64String: string): string => {
  const match = base64String.match(/^data:(image\/[a-zA-Z]+);base64,/);
  return match ? match[1] : 'image/jpeg';
};

const extractBase64Data = (base64String: string): string => {
  if (base64String.includes(',')) {
    return base64String.split(',')[1];
  }
  return base64String;
};

export const testConnection = async (): Promise<{ success: boolean; error?: string }> => {
  const key = process.env.API_KEY;
  console.log("[Lumina-Diagnostic] Testing connection with:", MODEL_CHAT);

  if (!key || key.length < 5) {
    console.error("[Lumina-Diagnostic] API Key missing or invalid.");
    return { success: false, error: 'Key Missing' };
  }

  try {
    const ai = new GoogleGenAI({ apiKey: key });
    // Using a simple prompt to verify key functionality
    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: "ping",
      config: { 
        maxOutputTokens: 5,
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    if (response.text) {
      console.log("[Lumina-Diagnostic] Connection confirmed.");
      return { success: true };
    }
    return { success: false, error: 'Empty Response' };
  } catch (error: any) {
    console.error("[Lumina-Diagnostic] Test failed:", error.message);
    return { success: false, error: error.message };
  }
};

export const generateReimaginedDesign = async (
  originalImageBase64: string,
  style: DesignStyle
): Promise<string | null> => {
  console.log(`[Lumina-API] Requesting redesign: ${style}`);

  const key = process.env.API_KEY;
  if (!key) throw new Error("API_KEY_MISSING");

  const ai = new GoogleGenAI({ apiKey: key });
  const mimeType = extractMimeType(originalImageBase64);
  const base64Data = extractBase64Data(originalImageBase64);

  const prompt = `Act as a professional interior designer. Transform this room into a high-end ${style} space. Keep the architectural structure (walls, windows, layout) identical to the original image. Replace all furniture, flooring, textures, and lighting with professional ${style} elements. Output must be a photorealistic architectural photograph.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: prompt }
        ]
      },
      config: { 
        imageConfig: { 
          aspectRatio: "1:1"
        }
      }
    });

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          console.log("[Lumina-API] Redesign successful.");
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
    throw new Error("NO_IMAGE_IN_RESPONSE");
  } catch (error: any) {
    console.error("[Lumina-API] Design Generation Error:", error);
    throw error;
  }
};

