import { GoogleGenAI } from "@google/genai";
import { DesignStyle, ChatLink } from "../types";

// Using the most reliable production-ready models
const MODEL_IMAGE = 'gemini-2.5-flash-image'; 
const MODEL_CHAT = 'gemini-3-flash-preview';

const extractMimeType = (base64String: string): string => {
  const match = base64String.match(/^data:(image\/[a-zA-Z]+);base64,/);
  return match ? match[1] : 'image/jpeg';
};

const extractBase64Data = (base64String: string): string => {
  if (base64String.includes(',')) {
    return base64String.split(',')[1];
  }
  return base64String;
};

export const testConnection = async (): Promise<{ success: boolean; error?: string }> => {
  const key = process.env.API_KEY;
  if (!key || key.length < 5) {
    return { success: false, error: 'API Key Missing' };
  }

  try {
    const ai = new GoogleGenAI({ apiKey: key });
    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: "ping",
      config: { maxOutputTokens: 5 }
    });
    return { success: !!response.text };
  } catch (error: any) {
    console.error("[Lumina] Connection failed:", error.message);
    return { success: false, error: error.message };
  }
};

export const generateReimaginedDesign = async (
  originalImageBase64: string,
  style: DesignStyle
): Promise<string | null> => {
  const key = process.env.API_KEY;
  if (!key) throw new Error("API_KEY_MISSING");

  const ai = new GoogleGenAI({ apiKey: key });
  const mimeType = extractMimeType(originalImageBase64);
  const base64Data = extractBase64Data(originalImageBase64);

  const prompt = `You are a world-class luxury interior designer. Redesign this room into the ${style} style. 
  IMPORTANT: Preserve the structural walls, window positions, and floor plan exactly. 
  Replace all furniture, lighting fixtures, color palettes, and decor with professional ${style} elements. 
  The output must be a single, photorealistic, high-resolution architectural photograph.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: prompt }
        ]
      },
      config: { imageConfig: { aspectRatio: "1:1" } }
    });

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
    throw new Error("No image was returned by the model.");
  } catch (error: any) {
    console.error("[Lumina] Generation Error:", error);
    throw error;
  }
};

export const getDesignAdvice = async (
  userPrompt: string,
  imageBase64?: string
): Promise<{ text: string; links?: ChatLink[] }> => {
  const key = process.env.API_KEY;
  if (!key) return { text: "API Key is not configured correctly." };

  const ai = new GoogleGenAI({ apiKey: key });
  const systemInstruction = `You are Lumina, a luxury interior design consultant. 
  Analyze user spaces and provide sophisticated advice. Recommend specific furniture items, 
  color codes, and layouts. Always be professional, helpful, and concise. Use Markdown.`;

  try {
    const parts: any[] = [{ text: userPrompt }];
    if (imageBase64) {
      parts.push({
        inlineData: {
          data: extractBase64Data(imageBase64),
          mimeType: extractMimeType(imageBase64)
        }
      });
    }

    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: { parts },
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
      }
    });

    const text = response.text || "I apologize, I'm having trouble processing that right now.";
    const links: ChatLink[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          links.push({ uri: chunk.web.uri, title: chunk.web.title });
        }
      });
    }

    return { text, links: links.length > 0 ? links : undefined };
  } catch (error) {
    console.error("[Lumina] Advice Error:", error);
    return { text: "My design servers are temporarily unreachable. Please check your connection." };
  }
};

