              <Text style={styles.statusText}>{apiStatus === 'connected' ? 'Service Online' : apiStatus === 'checking' ? 'Connecting...' : 'Service Offline'}</Text>
            </View>
          </View>
          {originalImage && (
            <TouchableOpacity onPress={() => setOriginalImage(null)} style={styles.resetBtn}>
              <Text style={styles.resetBtnText}>New Project</Text>
            </TouchableOpacity>
          )}
        </View>

        <ScrollView style={styles.content} contentContainerStyle={styles.scrollContent} showsVerticalScrollIndicator={false}>
          {!originalImage ? (
            <View style={styles.welcomeContainer}>
              <View style={styles.heroSection}>
                <View style={styles.badge}><Text style={styles.badgeText}>ELITE INTERIOR AI</Text></View>
                <Text style={styles.heroTitle}>Transform Your Space Instantly</Text>
                <Text style={styles.heroSubtitle}>Upload a photo and let our AI create a professional redesign in your favorite style.</Text>
              </View>
              <ImageInput onImageSelected={handleImageInput} />
            </View>
          ) : (
            <View style={styles.studio}>
              <View style={styles.viewer}>
                {isGenerating && (
                  <View style={styles.loaderOverlay}>
                    <ActivityIndicator size="large" color="#6366f1" />
                    <Text style={styles.loaderText}>Styling with {selectedStyle}...</Text>
                    <Text style={styles.loaderSubText}>Processing textures, lighting, and materials.</Text>
