import { generateReimaginedDesign, testConnection } from './services/geminiService';

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [apiStatus, setApiStatus] = useState<'checking' | 'connected' | 'error'>('checking');

  useEffect(() => {
    initialCheck();
  }, []);

  const getAiStudio = () => {
    if (typeof window !== 'undefined' && (window as any).aistudio) {
      return (window as any).aistudio;
    }
    return null;
  };

  const initialCheck = async () => {
    setApiStatus('checking');
    const aistudio = getAiStudio();
    if (Platform.OS === 'web' && aistudio) {
      try {
        const hasKey = await aistudio.hasSelectedApiKey();
        if (!hasKey) {
          setNeedsKey(true);
          setApiStatus('error');
          return;
        }
      } catch (e) {
        console.warn("Studio check bypassed.");
      }
    }
    await performApiTest();
  };

  const performApiTest = async () => {
    setApiStatus('checking');
    const result = await testConnection();
    if (result.success) {
      setApiStatus('connected');
      setNeedsKey(false);
    } else {
      setApiStatus('error');
      if (getAiStudio()) setNeedsKey(true);
    }
  };

  const handleOpenKeyPicker = async () => {
    const aistudio = getAiStudio();
    if (aistudio) {
      try {
        await aistudio.openSelectKey();
        setNeedsKey(false);
        setTimeout(performApiTest, 800);
      } catch (e) {
        console.error("Picker error:", e);
      }
    }
  };

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage) {
      Alert.alert("Notice", "Please upload a photo of your space first.");
      return;
    }
    if (apiStatus !== 'connected') {
      Alert.alert("API Service", "Reconnecting to servers. Ensure your API key is valid.", [
        { text: "Retry", onPress: performApiTest },
        { text: "Update Key", onPress: handleOpenKeyPicker },
        { text: "Cancel", style: "cancel" }
      ]);
      return;
    }
    if (isGenerating) return;

    setSelectedStyle(style);
    setIsGenerating(true);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      } else {
        throw new Error("Generation produced no result.");
      }
    } catch (e: any) {
      console.error("[App] Design Error:", e);
      Alert.alert("Design Failed", e.message || "Something went wrong during the makeover.");
      setSelectedStyle(null);
    } finally {
      setIsGenerating(false);
    }
  };

  if (needsKey && getAiStudio()) {
    return (
      <SafeAreaView style={styles.safeArea}>
        <View style={styles.centerContainer}>
          <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
          <View style={styles.setupCard}>
            <Text style={styles.setupTitle}>Premium Design AI</Text>
            <Text style={styles.setupSub}>To unlock luxury AI interior transformations, please connect your Gemini API key from a Paid Project.</Text>
            <TouchableOpacity style={styles.primaryBtn} onPress={handleOpenKeyPicker}>
              <Text style={styles.primaryBtnText}>Connect API Key</Text>
            </TouchableOpacity>
            <TouchableOpacity onPress={() => Linking.openURL('https://ai.google.dev/gemini-api/docs/billing')} style={styles.linkContainer}>
              <Text style={styles.linkText}>Billing & API Guide ↗</Text>
            </TouchableOpacity>
          </View>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.safeArea}>
      <StatusBar barStyle="dark-content" />
      <KeyboardAvoidingView behavior={Platform.OS === 'ios' ? 'padding' : 'height'} style={styles.container}>
        <View style={styles.header}>
          <View>
            <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
            <View style={styles.apiStatusRow}>
              <View style={[styles.statusDot, { backgroundColor: apiStatus === 'connected' ? '#10b981' : apiStatus === 'checking' ? '#f59e0b' : '#ef4444' }]} />
              <Text style={styles.statusText}>{apiStatus === 'connected' ? 'Service Online' : apiStatus === 'checking' ? 'Connecting...' : 'Service Offline'}</Text>
            </View>
          </View>
          {originalImage && (
            <TouchableOpacity onPress={() => setOriginalImage(null)} style={styles.resetBtn}>
              <Text style={styles.resetBtnText}>New Project</Text>
            </TouchableOpacity>
          )}
        </View>

        <ScrollView style={styles.content} contentContainerStyle={styles.scrollContent} showsVerticalScrollIndicator={false}>
          {!originalImage ? (
            <View style={styles.welcomeContainer}>
              <View style={styles.heroSection}>
                <View style={styles.badge}><Text style={styles.badgeText}>ELITE INTERIOR AI</Text></View>
                <Text style={styles.heroTitle}>Transform Your Space Instantly</Text>
                <Text style={styles.heroSubtitle}>Upload a photo and let our AI create a professional redesign in your favorite style.</Text>
              </View>
              <ImageInput onImageSelected={handleImageInput} />
            </View>
          ) : (
            <View style={styles.studio}>
              <View style={styles.viewer}>
                {isGenerating && (
                  <View style={styles.loaderOverlay}>
                    <ActivityIndicator size="large" color="#6366f1" />
                    <Text style={styles.loaderText}>Styling with {selectedStyle}...</Text>
                    <Text style={styles.loaderSubText}>Processing textures, lighting, and materials.</Text>
                  </View>
                )}
                <CompareSlider original={originalImage} modified={modifiedImage || originalImage} />
              </View>

              <StyleCarousel onSelect={handleStyleSelect} selectedStyle={selectedStyle} isGenerating={isGenerating} />

              <View style={styles.chatSection}>
                <Text style={styles.sectionTitle}>Consultant Chat</Text>
                <ChatInterface currentImage={modifiedImage || originalImage} onEditRequested={() => {}} />
              </View>
            </View>
          )}
        </ScrollView>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
};

