import { GoogleGenAI } from "@google/genai";
import { DesignStyle, ChatLink } from "../types";

const MODEL_IMAGE = 'gemini-2.5-flash-image'; 
const MODEL_CHAT = 'gemini-3-flash-preview';

const extractMimeType = (base64String: string): string => {
  const match = base64String.match(/^data:(image\/[a-zA-Z]+);base64,/);
  return match ? match[1] : 'image/jpeg';
};

const extractBase64Data = (base64String: string): string => {
  if (base64String.includes(',')) {
    return base64String.split(',')[1];
  }
  return base64String;
};

// Always create GoogleGenAI instance inside the function to use the latest API key from the environment
export const testConnection = async (): Promise<{ success: boolean; error?: string }> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: "ping",
    });
    return { success: !!response.text };
  } catch (error: any) {
    console.error("[Lumina] Connection test failed:", error.message);
    return { success: false, error: error.message };
  }
};

export const generateReimaginedDesign = async (
  originalImageBase64: string,
  style: DesignStyle
): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
  const mimeType = extractMimeType(originalImageBase64);
  const base64Data = extractBase64Data(originalImageBase64);

  const prompt = `You are a world-class luxury interior designer. Redesign this room into the ${style} style. 
  IMPORTANT: Preserve the structural walls, window positions, and floor plan exactly. 
  Replace all furniture, lighting, and decor with ${style} elements. 
  The result must be a photorealistic high-resolution interior photograph.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: prompt }
        ]
      },
      config: { imageConfig: { aspectRatio: "1:1" } }
    });

    if (response.candidates?.[0]?.content?.parts) {
      // Find the image part as the response may contain both image and text
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
    throw new Error("Design generation failed - no image returned.");
  } catch (error: any) {
    console.error("[Lumina] Design Generation Error:", error);
    throw error;
  }
};

export const getDesignAdvice = async (
  userPrompt: string,
  imageBase64?: string
): Promise<{ text: string; links?: ChatLink[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
  const systemInstruction = `You are Lumina, a luxury interior design consultant. Analyze the image and provide advice on furniture, lighting, and color schemes. Recommend specific styles. Use Markdown.`;

  try {
    const parts: any[] = [{ text: userPrompt }];
    if (imageBase64) {
      parts.push({
        inlineData: {
          data: extractBase64Data(imageBase64),
          mimeType: extractMimeType(imageBase64)
        }
      });
    }

    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: { parts },
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
      }
    });

    const text = response.text || "I'm sorry, I couldn't generate a response.";
    const links: ChatLink[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    // Extract website URLs from grounding chunks as required for Google Search grounding
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) links.push({ uri: chunk.web.uri, title: chunk.web.title });
      });
    }

    return { text, links: links.length > 0 ? links : undefined };
  } catch (error) {
    console.error("[Lumina] Advice Service Error:", error);
    return { text: "I'm having trouble connecting to my design database. Please check your connection." };
  }
};

import React, { useState, useEffect } from 'react';
import { 
  StyleSheet, 
  View, 
  Text, 
  ScrollView, 
  SafeAreaView, 
  TouchableOpacity, 
  Alert,
  ActivityIndicator,
  StatusBar,
  Platform,
  KeyboardAvoidingView,
  Linking
} from 'react-native';
import ImageInput from './components/ImageInput';
import StyleCarousel from './components/StyleCarousel';
import CompareSlider from './components/CompareSlider';
import ChatInterface from './components/ChatInterface';
import { DesignStyle } from './types';
import { generateReimaginedDesign, testConnection } from './services/geminiService';

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [apiStatus, setApiStatus] = useState<'checking' | 'connected' | 'error'>('checking');

  useEffect(() => {
    initialCheck();
  }, []);

  const getAiStudio = () => {
    if (typeof window !== 'undefined' && (window as any).aistudio) {
      return (window as any).aistudio;
    }
    return null;
  };

  const initialCheck = async () => {
    setApiStatus('checking');
    const aistudio = getAiStudio();
    if (Platform.OS === 'web' && aistudio) {
      try {
        const hasKey = await aistudio.hasSelectedApiKey();
        if (!hasKey) {
          setNeedsKey(true);
          setApiStatus('error');
          return;
        }
      } catch (e) {
        console.warn("Studio check bypassed.");
      }
    }
    await performApiTest();
  };

  const performApiTest = async () => {
    setApiStatus('checking');
    try {
      const result = await testConnection();
      if (result.success) {
        setApiStatus('connected');
        setNeedsKey(false);
      } else {
        setApiStatus('error');
        if (getAiStudio()) setNeedsKey(true);
      }
    } catch (err) {
      setApiStatus('error');
    }
  };

  const handleOpenKeyPicker = async () => {
    const aistudio = getAiStudio();
    if (aistudio) {
      try {
        await aistudio.openSelectKey();
        // Mitigate race condition: assume successful selection and proceed immediately
        setNeedsKey(false);
        performApiTest();
      } catch (e) {
        console.error("Picker error:", e);
      }
    }
  };

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage) {
      Alert.alert("Step 1", "Please upload a photo of your space first.");
      return;
    }
    if (apiStatus !== 'connected') {
      Alert.alert("Service Connection", "Re-establishing connection to Gemini AI...", [
        { text: "Retry", onPress: performApiTest },
        { text: "Update Key", onPress: handleOpenKeyPicker }
      ]);
      return;
    }
    if (isGenerating) return;

    setSelectedStyle(style);
    setIsGenerating(true);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      } else {
        throw new Error("Designer failed to generate the image.");
      }
    } catch (e: any) {
      console.error("[App] Design Error:", e);
      // Reset key selection state and prompt user to select a key again if 404 error occurs
      if (e.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
        handleOpenKeyPicker();
      } else {
        Alert.alert("Makeover Error", e.message || "Something went wrong during generation.");
      }
      setSelectedStyle(null);
    } finally {
      setIsGenerating(false);
    }
  };

  if (needsKey && getAiStudio()) {
    return (
      <View style={styles.centerContainer}>
        <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
        <View style={styles.setupCard}>
          <Text style={styles.setupTitle}>Connect AI Engine</Text>
          <Text style={styles.setupSub}>To start designing, please select your Gemini API key from a paid GCP project.</Text>
          <TouchableOpacity style={styles.primaryBtn} onPress={handleOpenKeyPicker}>
            <Text style={styles.primaryBtnText}>Select Key</Text>
          </TouchableOpacity>
          <TouchableOpacity onPress={() => Linking.openURL('https://ai.google.dev/gemini-api/docs/billing')} style={styles.linkContainer}>
            <Text style={styles.linkText}>View Billing Requirements ↗</Text>
          </TouchableOpacity>
        </View>
      </View>
    );
  }

  return (
    <SafeAreaView style={styles.safeArea}>
      <StatusBar barStyle="dark-content" />
      <KeyboardAvoidingView behavior={Platform.OS === 'ios' ? 'padding' : 'height'} style={styles.container}>
        <View style={styles.header}>
          <View>
