import React, { useState, useEffect } from 'react';
import { 
  StyleSheet, 
  View, 
  Text, 
  ScrollView, 
  SafeAreaView, 
  TouchableOpacity, 
  Alert,
  ActivityIndicator,
  StatusBar,
  Platform,
  KeyboardAvoidingView,
  Linking
} from 'react-native';
import ImageInput from './components/ImageInput';
import StyleCarousel from './components/StyleCarousel';
import CompareSlider from './components/CompareSlider';
import ChatInterface from './components/ChatInterface';
import { DesignStyle } from './types';
import { generateReimaginedDesign, testConnection } from './services/geminiService';

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [apiStatus, setApiStatus] = useState<'checking' | 'connected' | 'error'>('checking');

  useEffect(() => {
    initialCheck();
  }, []);

  const getAiStudio = () => {
    if (typeof window !== 'undefined' && (window as any).aistudio) {
      return (window as any).aistudio;
    }
    return null;
  };

  const initialCheck = async () => {
    setApiStatus('checking');
    const aistudio = getAiStudio();

    // Always check for a key if in AI Studio environment
    if (Platform.OS === 'web' && aistudio) {
      try {
        const hasKey = await aistudio.hasSelectedApiKey();
        if (!hasKey) {
          setNeedsKey(true);
          setApiStatus('error');
          return;
        }
      } catch (e) {
        console.warn("API Key check skipped");
      }
    }
    await performApiTest();
  };

  const performApiTest = async () => {
    setApiStatus('checking');
    try {
      const result = await testConnection();
      if (result.success) {
        setApiStatus('connected');
        setNeedsKey(false);
      } else {
        setApiStatus('error');
        // Fallback to manual selection if test fails
        if (getAiStudio()) setNeedsKey(true);
      }
    } catch (err) {
      setApiStatus('error');
    }
  };

  const handleOpenKeyPicker = async () => {
    const aistudio = getAiStudio();
    if (aistudio) {
      try {
        await aistudio.openSelectKey();
        setNeedsKey(false);
        // Direct jump to test after selection
        performApiTest();
      } catch (e) {
        console.error("Key selection failed", e);
      }
    }
  };

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage) {
      Alert.alert("Notice", "Please upload a room photo first.");
      return;
    }

    // Ensure we have a working connection
    if (apiStatus !== 'connected') {
      await performApiTest();
      if (apiStatus !== 'connected') {
        Alert.alert("Connection Required", "Please ensure your API key is configured.");
        return;
      }
    }

    if (isGenerating) return;

    setSelectedStyle(style);
    setIsGenerating(true);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      }
    } catch (e: any) {
      console.error("Generation error:", e);
      if (e.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
        handleOpenKeyPicker();
      } else {
        Alert.alert("Design Error", "We couldn't process your design. Please try again.");
      }
      setSelectedStyle(null);
    } finally {
      setIsGenerating(false);
    }
  };

  // If a key is required by the environment, show the prompt
  if (needsKey && getAiStudio()) {
    return (
      <View style={styles.centerContainer}>
        <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
        <View style={styles.setupCard}>
          <Text style={styles.setupTitle}>AI Setup Required</Text>
          <Text style={styles.setupSub}>To unlock the interior designer, please connect your Gemini API key.</Text>
          <TouchableOpacity style={styles.primaryBtn} onPress={handleOpenKeyPicker}>
            <Text style={styles.primaryBtnText}>Connect API Key</Text>
          </TouchableOpacity>
          <TouchableOpacity onPress={() => Linking.openURL('https://ai.google.dev/gemini-api/docs/billing')} style={styles.linkContainer}>
            <Text style={styles.linkText}>Learn about API billing ↗</Text>
          </TouchableOpacity>
        </View>
      </View>
    );
  }

  return (
    <SafeAreaView style={styles.safeArea}>
      <StatusBar barStyle="dark-content" />
      <View style={styles.mainWrapper}>
        <View style={styles.header}>
          <View>
            <Text style={styles.logoText}>Lumina<Text style={styles.logoAccent}>Space</Text></Text>
            <View style={styles.apiStatusRow}>
              <View style={[styles.statusDot, { backgroundColor: apiStatus === 'connected' ? '#10b981' : '#f59e0b' }]} />
              <Text style={styles.statusText}>{apiStatus === 'connected' ? 'AI Ready' : 'Connecting...'}</Text>
            </View>
          </View>
          {originalImage && (
            <TouchableOpacity onPress={() => setOriginalImage(null)} style={styles.resetBtn}>
              <Text style={styles.resetBtnText}>Reset</Text>
            </TouchableOpacity>
          )}
        </View>

        <ScrollView style={styles.scroll} contentContainerStyle={styles.scrollContent}>
          {!originalImage ? (
            <View style={styles.welcome}>
              <View style={styles.hero}>
                <View style={styles.badge}><Text style={styles.badgeText}>SMART DESIGN</Text></View>
                <Text style={styles.heroTitle}>Reimagine Your Room</Text>
                <Text style={styles.heroSubtitle}>Instant AI-powered interior redesign. Professional styles at your fingertips.</Text>
              </View>
              <ImageInput onImageSelected={handleImageInput} />
            </View>
          ) : (
            <View style={styles.studio}>
              <View style={styles.viewer}>
                {isGenerating && (
                  <View style={styles.loader}>
                    <ActivityIndicator size="large" color="#4f46e5" />
                    <Text style={styles.loaderTitle}>Styling Room...</Text>
                  </View>
                )}
                <CompareSlider original={originalImage} modified={modifiedImage || originalImage} />
              </View>

              <StyleCarousel onSelect={handleStyleSelect} selectedStyle={selectedStyle} isGenerating={isGenerating} />

              <View style={styles.chatSection}>
                <Text style={styles.sectionHeader}>Design Consultation</Text>
                <ChatInterface currentImage={modifiedImage || originalImage} onEditRequested={() => {}} />
              </View>
            </View>
          )}
        </ScrollView>
      </View>
    </SafeAreaView>
  );
};

