import { generateReimaginedDesign, editDesign } from './services/geminiService';

const STORAGE_KEY = 'lumina_saved_designs';

// Declare AI Studio globals for TypeScript
declare global {
  /**
   * Fixes conflicting global declaration of window.aistudio.
   * Ensures the type name matches 'AIStudio' and includes 'readonly' modifier as required by the environment.
   */
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    readonly aistudio: AIStudio;
  }
}

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [hasApiKey, setHasApiKey] = useState<boolean>(true); // Assume true unless check fails

  // Load saved designs and check for API Key on mount
  useEffect(() => {
    const checkApiKey = async () => {
      if (window.aistudio) {
        try {
          const hasKey = await window.aistudio.hasSelectedApiKey();
          setHasApiKey(hasKey);
        } catch (e) {
          console.error("Error checking API key status", e);
        }
      }
    };
    checkApiKey();

    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      try {
        setSavedDesigns(JSON.parse(stored));
      } catch (e) {
        console.error("Failed to parse saved designs", e);
      }
    }
  }, []);

  const handleSelectKey = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      // Proceed assuming success per race condition instructions
      setHasApiKey(true);
    }
  };

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
    setError(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage || isGenerating) return;

    setSelectedStyle(style);
    setIsGenerating(true);
    setError(null);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      } else {
        setError("The design generation failed. This might be due to an invalid API key or service unavailability.");
      }
    } catch (e: any) {
      const errMsg = e.message || "An unexpected error occurred during design generation.";
      setError(errMsg);
      // If the error looks like an auth or not found error, prompt for key selection
      if (errMsg.includes('404') || errMsg.toLowerCase().includes('not found') || errMsg.toLowerCase().includes('api key')) {
        setHasApiKey(false);
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const handleShuffleStyle = () => {
    if (!originalImage || isGenerating) return;
    const allStyles = Object.values(DesignStyle);
    const availableStyles = allStyles.filter(s => s !== selectedStyle);
    const randomStyle = availableStyles[Math.floor(Math.random() * availableStyles.length)];
    handleStyleSelect(randomStyle);
  };

  const handleEditRequested = async (instruction: string) => {
    const baseImage = modifiedImage || originalImage;
    if (!baseImage || isGenerating) return;

    setIsGenerating(true);
    setError(null);
    try {
      const result = await editDesign(baseImage, instruction);
      if (result) {
        setModifiedImage(result);
      } else {
        setError("Could not edit the design. Try a different request.");
      }
    } catch (e: any) {
      const errMsg = e.message || "An error occurred during editing.";
      setError(errMsg);
      if (errMsg.toLowerCase().includes('404') || errMsg.toLowerCase().includes('not found')) {
        setHasApiKey(false);
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSaveDesign = () => {
    if (!originalImage || !modifiedImage || !selectedStyle) return;

    const newSaved: SavedDesign = {
      id: Date.now().toString(),
      originalImage,
      modifiedImage,
      style: selectedStyle,
      timestamp: Date.now()
    };

    const updated = [newSaved, ...savedDesigns];
    setSavedDesigns(updated);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  };

  const handleLoadSaved = (saved: SavedDesign) => {
    setOriginalImage(saved.originalImage);
    setModifiedImage(saved.modifiedImage);
    setSelectedStyle(saved.style);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteSaved = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const updated = savedDesigns.filter(d => d.id !== id);
    setSavedDesigns(updated);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
      {/* API Key Selection Overlay */}
      {!hasApiKey && (
        <div className="fixed inset-0 z-[100] bg-slate-900/90 backdrop-blur-sm flex items-center justify-center p-4">
