import React, { useState, useEffect } from 'react';
import ImageInput from './components/ImageInput';
import StyleCarousel from './components/StyleCarousel';
import CompareSlider from './components/CompareSlider';
import ChatInterface from './components/ChatInterface';
import { DesignStyle, SavedDesign } from './types';
import { generateReimaginedDesign, editDesign } from './services/geminiService';

const STORAGE_KEY = 'lumina_saved_designs';

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);

  // Load saved designs on mount
  useEffect(() => {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      try {
        setSavedDesigns(JSON.parse(stored));
      } catch (e) {
        console.error("Failed to parse saved designs", e);
      }
    }
  }, []);

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
    setError(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage || isGenerating) return;

    setSelectedStyle(style);
    setIsGenerating(true);
    setError(null);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      } else {
        setError("Generation failed. This can happen if the room photo is too dark or the AI service is temporarily busy.");
      }
    } catch (e: any) {
      setError(e.message || "An unexpected error occurred. Please try again in a few moments.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleShuffleStyle = () => {
    if (!originalImage || isGenerating) return;
    const allStyles = Object.values(DesignStyle);
    const availableStyles = allStyles.filter(s => s !== selectedStyle);
    const randomStyle = availableStyles[Math.floor(Math.random() * availableStyles.length)];
    handleStyleSelect(randomStyle);
  };

  const handleEditRequested = async (instruction: string) => {
    const baseImage = modifiedImage || originalImage;
    if (!baseImage || isGenerating) return;

    setIsGenerating(true);
    setError(null);
    try {
      const result = await editDesign(baseImage, instruction);
      if (result) {
        setModifiedImage(result);
      } else {
        setError("Modification failed. Please try a more specific request (e.g., 'Add a plant in the corner').");
      }
    } catch (e: any) {
      setError(e.message || "An error occurred during editing.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSaveDesign = () => {
    if (!originalImage || !modifiedImage || !selectedStyle) return;

    const newSaved: SavedDesign = {
      id: Date.now().toString(),
      originalImage,
      modifiedImage,
      style: selectedStyle,
      timestamp: Date.now()
    };

    const updated = [newSaved, ...savedDesigns];
    setSavedDesigns(updated);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  };

  const handleLoadSaved = (saved: SavedDesign) => {
    setOriginalImage(saved.originalImage);
    setModifiedImage(saved.modifiedImage);
    setSelectedStyle(saved.style);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteSaved = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const updated = savedDesigns.filter(d => d.id !== id);
    setSavedDesigns(updated);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
