                <div className="max-w-xl mx-auto space-y-4">
                  <h2 className="text-4xl md:text-5xl font-bold text-slate-900 tracking-tight font-display leading-tight">Reimagine your space in seconds</h2>
                  <p className="text-slate-500 text-lg">Snap a photo or upload an image of any room to see it reborn with professional interior design styles.</p>
                </div>
                <ImageInput onImageSelected={handleImageInput} />
              </div>
