                  </div>
                </div>

                <div className="relative group">
                  {isGenerating && (
                    <div className="absolute inset-0 z-20 bg-white/70 backdrop-blur-md rounded-2xl flex flex-col items-center justify-center p-8 text-center animate-in fade-in">
                      <div className="relative mb-6">
