                      </div>
                      <h4 className="text-2xl font-bold text-slate-900 font-display">Curating your space...</h4>
                      <p className="text-slate-500 max-w-xs mt-3">Rendering the {selectedStyle ? String(selectedStyle) : 'new'} aesthetic.</p>
