import { GoogleGenAI } from "@google/genai";
import { DesignStyle, ChatLink } from "../types";

/**
 * Using Pro models for highest quality and better reasoning.
 * Redesign: gemini-3-pro-image-preview
 * Consultant: gemini-3-pro-preview
 */
const MODEL_IMAGE = 'gemini-3-pro-image-preview';
const MODEL_CHAT = 'gemini-3-pro-preview';

const cleanBase64 = (base64: string): string => {
  if (typeof base64 !== 'string') return '';
  if (base64.includes(',')) {
    return base64.split(',')[1];
  }
  return base64;
};

export const generateReimaginedDesign = async (
  originalImageBase64: string,
  style: DesignStyle
): Promise<string | null> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("Missing API Key. Please connect your Google AI Studio account.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `You are an elite interior designer. Completely redesign this room in the ${style} style. 
  Preserve the structural geometry (walls, windows, doors) but replace everything else: floor, ceiling, lighting, furniture, and decor. 
  Ensure the result is photorealistic, beautifully lit, and high-resolution.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: {
        parts: [
          {
            inlineData: {
              data: cleanBase64(originalImageBase64),
              mimeType: 'image/png'
            }
          },
          { text: prompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "1K"
        }
      }
    });

    const candidates = response.candidates;
    if (candidates && candidates.length > 0) {
      for (const part of candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
  } catch (error: any) {
    console.error("Redesign API Error:", error);
    if (error.message?.includes("entity was not found")) {
      throw new Error("API Project Error: Please ensure your API key is from a paid GCP project.");
    }
    throw new Error(`Design Generation Failed: ${error.message}`);
  }
  return null;
};

export const editDesign = async (
  currentImageBase64: string,
  instruction: string
): Promise<string | null> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("Missing API Key.");

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: {
        parts: [
          {
            inlineData: {
              data: cleanBase64(currentImageBase64),
              mimeType: 'image/png'
            }
          },
          { text: `Modify this design: ${instruction}. Maintain the existing style and lighting.` }
        ]
      }
    });

    const candidates = response.candidates;
    if (candidates && candidates.length > 0) {
      for (const part of candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
  } catch (error: any) {
    throw new Error(`Edit Failed: ${error.message}`);
  }
  return null;
};

export const getDesignAdvice = async (
  userPrompt: string,
  imageBase64?: string
): Promise<{ text: string; links?: ChatLink[] }> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("Missing API Key.");

  const ai = new GoogleGenAI({ apiKey });

  try {
    const parts: any[] = [{ text: userPrompt }];
    if (imageBase64) {
      parts.push({
        inlineData: {
          data: cleanBase64(imageBase64),
          mimeType: 'image/png'
        }
      });
    }

    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: { parts },
      config: {
        systemInstruction: "You are Lumina, a senior Interior Design Consultant. Provide detailed, expert advice on layout, color, and furniture. Be encouraging and professional.",
      }
    });

    return { text: response.text || "I'm processing your request..." };
  } catch (error: any) {
    throw new Error(`Consultation Error: ${error.message}`);
  }
};

import React, { useState, useEffect } from 'react';
import ImageInput from './components/ImageInput';
