                  <h2 className="text-2xl font-bold font-display">Design Studio</h2>
                  <div className="flex gap-2">
                    {modifiedImage && (
                      <button 
                        onClick={handleSaveDesign}
                        className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-sm font-bold shadow-md shadow-indigo-100"
                      >
                        Save Design
                      </button>
                    )}
                    <button 
                      onClick={() => setOriginalImage(null)}
