export const getDesignAdvice = async (
  userPrompt: string,
  imageBase64?: string
): Promise<{ text: string; links?: ChatLink[] }> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("Missing API Key.");

  // Create a new instance right before call as per guidelines
  const ai = new GoogleGenAI({ apiKey });

  try {
    const parts: any[] = [{ text: userPrompt }];
    if (imageBase64) {
      parts.push({
        inlineData: {
          data: cleanBase64(imageBase64),
          mimeType: 'image/png'
        }
      });
    }

    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: { parts },
      config: {
        systemInstruction: "You are Lumina, a senior Interior Design Consultant. Provide detailed, expert advice on layout, color, and furniture. Be encouraging and professional. Use Google Search to recommend real furniture and decor items where appropriate.",
        tools: [{ googleSearch: {} }]
      }
    });

    const text = response.text || "I'm processing your request...";
    const links: ChatLink[] = [];

    // Extracting URLs from groundingChunks as required by Search Grounding rules
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          links.push({
            uri: chunk.web.uri,
            title: chunk.web.title
          });
        }
      });
    }

    return { text, links };
  } catch (error: any) {
    throw new Error(`Consultation Error: ${error.message}`);
  }
};

