import ChatInterface from './components/ChatInterface';
import { DesignStyle, SavedDesign } from './types';
import { generateReimaginedDesign, editDesign } from './services/geminiService';

const STORAGE_KEY = 'lumina_saved_designs';

// Fix for TypeScript errors regarding multiple declarations of 'aistudio' on Window.
// We make it optional and inline to match the likely environment-provided definition.
declare global {
  interface Window {
    aistudio?: {
      hasSelectedApiKey(): Promise<boolean>;
      openSelectKey(): Promise<void>;
    };
  }
}

const App: React.FC = () => {
  // If process.env.API_KEY is already there (from Vercel), we start with hasKey = true
  const [hasKey, setHasKey] = useState<boolean>(!!process.env.API_KEY);
  const [isCheckingKey, setIsCheckingKey] = useState(true);

  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);

  useEffect(() => {
    const checkKey = async () => {
      // If Vercel key is missing, check if one was selected via AI Studio dialog
      if (!process.env.API_KEY && window.aistudio) {
        try {
          const selected = await window.aistudio.hasSelectedApiKey();
          setHasKey(selected);
        } catch (e) {
          setHasKey(false);
        }
      } else if (process.env.API_KEY) {
        setHasKey(true);
      }
      setIsCheckingKey(false);
    };

    checkKey();

    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      try {
        setSavedDesigns(JSON.parse(stored));
      } catch (e) {
        console.error("Failed to parse saved designs", e);
      }
    }
  }, []);

  const handleConnect = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      // Assume success after triggering the dialog to mitigate race conditions
      setHasKey(true); 
    } else {
      alert("API_KEY not detected. Please ensure you have set it in Vercel Project Settings and redeployed.");
    }
  };

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
    setError(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage || isGenerating) return;

    setSelectedStyle(style);
    setIsGenerating(true);
    setError(null);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      } else {
        setError("Failed to generate design. Please try again.");
      }
    } catch (e: any) {
      setError(e.message);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleEditRequested = async (instruction: string) => {
    const baseImage = modifiedImage || originalImage;
    if (!baseImage || isGenerating) return;

    setIsGenerating(true);
    setError(null);
    try {
      const result = await editDesign(baseImage, instruction);
      if (result) {
        setModifiedImage(result);
      }
    } catch (e: any) {
      setError(e.message);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSaveDesign = () => {
    if (!originalImage || !modifiedImage || !selectedStyle) return;
    const newSaved: SavedDesign = {
      id: Date.now().toString(),
      originalImage,
      modifiedImage,
      style: selectedStyle,
      timestamp: Date.now()
    };
    const updated = [newSaved, ...savedDesigns];
    setSavedDesigns(updated);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  };

  if (isCheckingKey) return null;

  if (!hasKey) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-white p-10 rounded-[2.5rem] shadow-xl border border-slate-100 text-center space-y-8">
          <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto shadow-lg shadow-indigo-100">
            <svg className="w-10 h-10 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
          </div>
          <div className="space-y-4">
            <h1 className="text-3xl font-bold text-slate-900 font-display">Connect Gemini API</h1>
            <p className="text-slate-500 text-sm">
              We couldn't detect your API key. If you added it to Vercel, make sure you redeployed. Otherwise, you can connect your Google AI Studio account below.
            </p>
            <div className="pt-4 flex flex-col gap-3">
              <button 
                onClick={handleConnect}
                className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 transition-all shadow-md"
              >
                Connect to Gemini
              </button>
              <a 
                href="https://ai.google.dev/gemini-api/docs/billing" 
                target="_blank" 
                className="text-xs text-indigo-600 font-medium hover:underline"
              >
                API Key Documentation
              </a>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
      <header className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-200 py-4 px-6 mb-8">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center">
              <svg className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
