  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [modifiedImage, setModifiedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState<DesignStyle | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);

  useEffect(() => {
    const checkKey = async () => {
      // 1. Check if key is baked into the environment variable
      const envKey = process.env.API_KEY;
      if (envKey && envKey.length > 5) {
        setHasKey(true);
      } 
      // 2. Otherwise check if AI Studio tool is providing a key
      else if (window.aistudio) {
        try {
          const selected = await window.aistudio.hasSelectedApiKey();
          setHasKey(selected);
        } catch (e) {
          setHasKey(false);
        }
      }
      setIsCheckingKey(false);
    };

    checkKey();

    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      try {
        setSavedDesigns(JSON.parse(stored));
      } catch (e) {
        console.error("Failed to parse saved designs", e);
      }
    }
  }, []);

  const handleConnect = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      // Assume success and move forward to bypass race conditions
      setHasKey(true); 
    } else {
      alert("API Key not found. Please ensure you have set API_KEY in Vercel and redeployed.");
    }
  };

  const handleImageInput = (base64: string) => {
    setOriginalImage(base64);
    setModifiedImage(null);
    setSelectedStyle(null);
    setError(null);
  };

  const handleStyleSelect = async (style: DesignStyle) => {
    if (!originalImage || isGenerating) return;

    setSelectedStyle(style);
    setIsGenerating(true);
    setError(null);

    try {
      const result = await generateReimaginedDesign(originalImage, style);
      if (result) {
        setModifiedImage(result);
      } else {
        setError("Generation timed out. Please try again.");
      }
    } catch (e: any) {
      if (e.message?.includes("Requested entity was not found.") && window.aistudio) {
        setHasKey(false);
        await window.aistudio.openSelectKey();
        setHasKey(true);
      } else {
        setError(e.message);
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const handleEditRequested = async (instruction: string) => {
    const baseImage = modifiedImage || originalImage;
    if (!baseImage || isGenerating) return;

    setIsGenerating(true);
    setError(null);
    try {
      const result = await editDesign(baseImage, instruction);
      if (result) {
        setModifiedImage(result);
      }
    } catch (e: any) {
