 * General Image generation/editing: gemini-2.5-flash-image
 * Interior design reasoning and consultant: gemini-3-flash-preview
 */
const MODEL_IMAGE = 'gemini-2.5-flash-image';
const MODEL_CHAT = 'gemini-3-flash-preview';

const cleanBase64 = (base64: string): string => {
  if (typeof base64 !== 'string') return '';
  if (base64.includes(',')) {
    return base64.split(',')[1];
  }
  return base64;
};

// Reimagines the design of a room based on a chosen style
export const generateReimaginedDesign = async (
  originalImageBase64: string,
  style: DesignStyle
): Promise<string | null> => {
  // Always initialize GoogleGenAI right before use to ensure the latest API key is used
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `You are an expert interior designer. Redesign this room completely in the ${style} interior design style. 
  Keep the basic room structure (walls and windows) but change all furniture, flooring, wall colors, and decor to match the ${style} aesthetic perfectly. 
  The output must be a single photorealistic, high-quality image of the new design.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: {
        parts: [
          {
            inlineData: {
              data: cleanBase64(originalImageBase64),
              mimeType: 'image/png'
            }
          },
          { text: prompt }
        ]
      }
    });

    const candidates = response.candidates;
    if (candidates && candidates.length > 0) {
      // Find the image part as the response may contain text or multiple parts
      for (const part of candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
  } catch (error: any) {
    console.error("Redesign API Error:", error);
    throw new Error(`Design Generation Failed: ${error.message}`);
  }
  return null;
};

