// Provides professional design advice using Google Search for grounding
export const getDesignAdvice = async (
  userPrompt: string,
  imageBase64?: string
): Promise<{ text: string; links?: ChatLink[] }> => {
  // Always initialize GoogleGenAI right before use
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const parts: any[] = [{ text: userPrompt }];
    if (imageBase64) {
      parts.push({
        inlineData: {
          data: cleanBase64(imageBase64),
          mimeType: 'image/png'
        }
      });
    }

    const response = await ai.models.generateContent({
      model: MODEL_CHAT,
      contents: { parts },
      config: {
        systemInstruction: "You are Lumina, a helpful AI Interior Design Consultant. Give specific, professional advice on room layouts, color palettes, and decor. Use Google Search to suggest actual furniture products.",
        tools: [{ googleSearch: {} }]
      }
    });

    // Directly access the text property from the response object
    const text = response.text || "I'm looking into that for you...";
    const links: ChatLink[] = [];

    // Extract search grounding metadata to display source links
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          links.push({
            uri: chunk.web.uri,
            title: chunk.web.title
          });
        }
      });
    }

    return { text, links };
  } catch (error: any) {
    throw new Error(`Consultation Error: ${error.message}`);
  }
};

